INSERT INTO questions (id, specialty, category, domain_name, subtopic, difficulty, stem, choices, correct_answer, explanation, "references", status, telemetry) VALUES
('authored-batch-r3-001', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Burn injury: succinylcholine-induced hyperkalemia and receptor upregulation', 'medium', 'A 34-year-old man is brought to the OR for serial excision and grafting of deep partial- and full-thickness flame burns covering 40% of his total body surface area. The injury occurred 12 days ago. He is hemodynamically stable on the ventilator and requires a brief deepening of anesthesia for line placement before grafting. The trainee asks for succinylcholine 1.5 mg/kg to facilitate a quick intubating-level relaxation. Shortly after a similar dose was given at an outside facility yesterday, the patient reportedly developed a wide-complex tachyarrhythmia. Which of the following best explains why succinylcholine is contraindicated in this patient at this time?', '[{"text":"Upregulation of extrajunctional (immature) acetylcholine receptors causes exaggerated potassium efflux and life-threatening hyperkalemia","label":"A","correct":true,"rationale":"Correct: after the first 24-48 hours, burns trigger proliferation of extrajunctional/fetal-type nicotinic receptors across the muscle membrane, so depolarization by succinylcholine releases a massive, potentially fatal potassium load."},{"text":"Burn-induced pseudocholinesterase deficiency markedly prolongs the duration of succinylcholine-induced paralysis","label":"B","correct":false,"rationale":"Incorrect: although plasma cholinesterase activity can fall with burns, prolonged block is not the lethal mechanism, and a modestly longer paralysis does not explain an acute malignant arrhythmia."},{"text":"Thermal injury sensitizes the myocardium so that the muscarinic effects of succinylcholine precipitate refractory bradyarrhythmias","label":"C","correct":false,"rationale":"Incorrect: succinylcholine can cause bradycardia (especially in children or with repeat dosing), but the described wide-complex tachyarrhythmia in a burn patient points to hyperkalemia, not a vagal effect."},{"text":"Burn patients reliably exhibit increased sensitivity to succinylcholine, so a standard dose produces a profound, unterminating block","label":"D","correct":false,"rationale":"Incorrect: burn patients are actually resistant to nondepolarizing agents from the same receptor upregulation, and the danger of succinylcholine is hyperkalemia, not an unusually deep or unterminating block."},{"text":"Succinylcholine triggers malignant hyperthermia in burn patients because thermal injury unmasks a latent RYR1 channelopathy","label":"E","correct":false,"rationale":"Incorrect: burns do not create malignant hyperthermia susceptibility, which is an inherited RYR1/CACNA1S trait unrelated to the acquired receptor changes of thermal injury."}]'::jsonb, 'A', 'Within hours of a major burn, denervation-type changes drive widespread upregulation of extrajunctional (immature/fetal-subtype) acetylcholine receptors. When succinylcholine depolarizes these receptors across the entire muscle membrane rather than just the endplate, the resulting potassium efflux can produce hyperkalemic cardiac arrest. The risk is minimal in the first ~48 hours but climbs sharply from about days 7-10 and can persist for up to 1-2 years until receptor populations normalize, so a nondepolarizing relaxant (e.g., rocuronium) should be used instead.', '[{"url":"https://www.openanesthesia.org/keywords/succinylcholine/","source":"Succinylcholine - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-002', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Inhalation injury: carbon monoxide poisoning and pulse oximetry limitations', 'easy', 'A 52-year-old man is rescued from a house fire and arrives obtunded with soot around the nares, singed nasal hairs, and a hoarse voice. He is breathing spontaneously on a non-rebreather mask. Vitals: HR 118, BP 138/84, RR 26, SpO2 99% on the pulse oximeter. He complains of severe headache and nausea and is intermittently confused. An arterial blood gas shows pH 7.30 with a normal PaO2 but a measured carboxyhemoglobin of 28%. Which statement best explains the discrepancy between his oximetry reading and his clinical condition, and the correct next step?', '[{"text":"The normal PaO2 confirms adequate tissue oxygen delivery, so observation alone on room air is appropriate once he is more alert","label":"A","correct":false,"rationale":"Incorrect: PaO2 reflects dissolved oxygen, not the oxygen-carrying capacity crippled by carboxyhemoglobin, so a normal PaO2 is misleading and observation on room air would prolong a dangerous CO half-life."},{"text":"Standard pulse oximetry cannot distinguish carboxyhemoglobin from oxyhemoglobin, so the SpO2 is falsely reassuring; he needs high-flow 100% oxygen","label":"B","correct":true,"rationale":"Correct: a conventional two-wavelength oximeter reads carboxyhemoglobin much like oxyhemoglobin and overestimates true saturation, so high-flow 100% oxygen (and consideration of hyperbaric therapy) is required to accelerate CO elimination."},{"text":"The high SpO2 indicates methemoglobinemia, which is best treated with intravenous methylene blue","label":"C","correct":false,"rationale":"Incorrect: methemoglobinemia classically drives SpO2 toward roughly 85%, and the measured carboxyhemoglobin identifies CO poisoning, for which methylene blue is not indicated."},{"text":"His symptoms are explained by cyanide toxicity alone, so 100% oxygen has no role and hydroxocobalamin should replace it","label":"D","correct":false,"rationale":"Incorrect: although concomitant cyanide toxicity can occur in enclosed-space fires, the documented carboxyhemoglobin of 28% mandates 100% oxygen, which is foundational therapy and is not replaced by hydroxocobalamin."},{"text":"The pulse oximeter is malfunctioning from motion and poor perfusion, so a finger rewarming maneuver will correct the reading","label":"E","correct":false,"rationale":"Incorrect: the reading is not an artifact of perfusion or motion but a predictable limitation of conventional oximetry in the presence of carboxyhemoglobin, which rewarming cannot fix."}]'::jsonb, 'B', 'Carboxyhemoglobin absorbs light similarly to oxyhemoglobin at the wavelengths used by conventional pulse oximeters, so the SpO2 can read near-normal despite severe impairment of oxygen-carrying capacity. Diagnosis requires direct co-oximetry measurement of carboxyhemoglobin, and PaO2 stays normal because it reflects only dissolved oxygen. Treatment is immediate high-flow 100% oxygen by non-rebreather (or via the ventilator), which shortens the CO half-life dramatically; hyperbaric oxygen is considered for severe poisoning such as neurologic impairment or very high carboxyhemoglobin levels.', '[{"url":"https://www.openanesthesia.org/keywords/carbon-monoxide-poisoning/","source":"Carbon Monoxide Poisoning - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-003', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Critical events: intraoperative venous air embolism detection and management', 'hard', 'A 58-year-old woman is undergoing a posterior fossa craniotomy in the sitting position under general anesthesia with controlled ventilation. About 90 minutes into the case, while the surgeon is working near a large dural venous sinus, the capnograph shows an abrupt drop in end-tidal CO2 from 34 to 19 mmHg, the SpO2 begins to fall, and the blood pressure declines from 118/70 to 82/48 mmHg. A precordial Doppler probe emits a sudden roaring/''mill-wheel'' change in tone. Which of the following is the most appropriate immediate action?', '[{"text":"Increase the inspired nitrous oxide concentration to maintain anesthetic depth while the surgeon controls the field","label":"A","correct":false,"rationale":"Incorrect: nitrous oxide diffuses into and expands entrained air bubbles, enlarging the embolus, so it must be discontinued rather than increased."},{"text":"Administer a fluid bolus and deepen anesthesia with additional volatile agent, then reassess in 10 minutes before acting further","label":"B","correct":false,"rationale":"Incorrect: a 10-minute delay during an ongoing air embolism is dangerous, and deepening volatile anesthetic does not stop air entrainment or address the hemodynamic collapse."},{"text":"Notify the surgeon to flood the surgical field with saline and stop air entry, discontinue nitrous oxide, and give 100% oxygen","label":"C","correct":true,"rationale":"Correct: the first priorities are halting further air entrainment (flood the field, occlude the open vessel, lower the head) while removing nitrous oxide and delivering 100% oxygen to support oxygenation and shrink the existing bubble."},{"text":"Immediately convert the patient to the reverse Trendelenburg (further head-up) position to encourage the air to rise out of the wound","label":"D","correct":false,"rationale":"Incorrect: head-up positioning keeps the operative site above the heart and promotes continued air entrainment, whereas the patient should be moved toward head-down/left-lateral to reduce further entry."},{"text":"Begin chest compressions and prepare for emergent sternotomy regardless of the rhythm, since air embolism mandates open cardiac massage","label":"E","correct":false,"rationale":"Incorrect: the patient still has a perfusing rhythm with a measurable blood pressure, so reflexive chest compressions and sternotomy are not the immediate step; source control and 100% oxygen come first."}]'::jsonb, 'C', 'A sudden fall in end-tidal CO2 with hemodynamic deterioration and a ''mill-wheel'' Doppler change during a sitting craniotomy is classic for venous air embolism, which occurs when the operative site sits above the level of the heart and air is entrained into open venous channels. The immediate response is to stop further air entry (alert the surgeon to flood the field and occlude the vessel, lower the head), discontinue nitrous oxide because it expands the air bubble, deliver 100% oxygen, and support the circulation with fluids and vasopressors; aspiration through a right-atrial catheter may also be attempted. Transesophageal echocardiography is the most sensitive intraoperative monitor for detecting entrained air.', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-004', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'One-lung ventilation: management of intraoperative hypoxemia', 'medium', 'A 64-year-old man with a 50-pack-year smoking history is undergoing a right upper lobectomy via right thoracotomy. A left-sided double-lumen tube is placed and confirmed by fiberoptic bronchoscopy. Twenty minutes after initiating one-lung ventilation of the dependent left lung with an FiO2 of 1.0, the SpO2 drifts from 98% to 84%. Peak airway pressures are unchanged, the capnogram is normal, and bilateral breath sounds over the dependent lung are clear. The surgeon is mid-dissection at the hilum and asks for one more minute. Which intervention is the most appropriate next step to improve oxygenation while permitting the surgeon to continue?', '[{"text":"Immediately deflate the bronchial cuff and resume two-lung ventilation","label":"A","correct":false,"rationale":"Incorrect: this is the definitive rescue for refractory or severe desaturation but fully re-expands the operative lung and halts surgery, which is not yet required when a graded measure can be tried first."},{"text":"Add 10 cm H2O of PEEP to the dependent ventilated lung alone","label":"B","correct":false,"rationale":"Incorrect: PEEP to the dependent lung can help recruit atelectasis but may also overdistend alveoli and divert blood flow toward the nonventilated lung, worsening shunt, so it is less reliably beneficial as a first maneuver than nondependent CPAP."},{"text":"Decrease the FiO2 to 0.6 to limit absorption atelectasis","label":"C","correct":false,"rationale":"Incorrect: lowering FiO2 during active hypoxemia reduces the alveolar oxygen available for the dependent lung and would deepen, not relieve, the desaturation."},{"text":"Apply 5-10 cm H2O of CPAP with oxygen to the nonventilated (operative) right lung","label":"D","correct":true,"rationale":"Correct: applying low-level CPAP to the collapsed nondependent lung oxygenates blood passing through it via residual perfusion without fully re-expanding the surgical field, addressing shunt while letting dissection continue."},{"text":"Administer a fluid bolus and start a phenylephrine infusion to raise cardiac output","label":"E","correct":false,"rationale":"Incorrect: the problem is intrapulmonary shunt, not hypovolemia, and raising perfusion to the nonventilated lung with vasoconstrictors that blunt hypoxic pulmonary vasoconstriction can worsen the shunt fraction."}]'::jsonb, 'D', 'Hypoxemia during one-lung ventilation is driven by transpulmonary shunt through the deliberately collapsed nondependent lung. After confirming tube position and FiO2 of 1.0, a graded response is appropriate: CPAP to the nonventilated lung is the classic next step because oxygen reaching residually perfused alveoli reduces shunt with minimal disruption of the surgical field. Reserve full two-lung ventilation for severe or refractory desaturation. Dependent-lung PEEP helps recruitment but can redistribute flow and is less consistently effective as the initial maneuver.', '[{"url":"https://www.openanesthesia.org/keywords/hypoxia-during-one-lung-ventilation/","source":"Hypoxia During One-Lung Ventilation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-005', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'Vascular surgery: aortic cross-clamp hemodynamic physiology', 'medium', 'A 71-year-old man undergoes open repair of an infrarenal abdominal aortic aneurysm. His baseline blood pressure is 138/80 mmHg. Immediately after the surgeon applies the infrarenal aortic cross-clamp, the radial arterial line shows a rise to 192/104 mmHg, central venous pressure increases, and the anesthesiologist notes a widening gap between the arterial and end-tidal CO2. Which physiologic change most directly explains the abrupt rise in arterial blood pressure seen at this moment?', '[{"text":"Reflex bradycardia-mediated increase in stroke volume from the baroreceptor response","label":"A","correct":false,"rationale":"Incorrect: any reflex bradycardia is a downstream response to the hypertension rather than its cause, and it does not generate the pressure rise itself."},{"text":"Release of vasodilatory metabolites from ischemic tissue distal to the clamp","label":"B","correct":false,"rationale":"Incorrect: ischemic metabolite washout causes hypotension and vasodilation at unclamping, the opposite of the hypertension seen immediately after clamp application."},{"text":"Catecholamine surge from inadequate anesthetic depth at the time of clamping","label":"C","correct":false,"rationale":"Incorrect: although light anesthesia can raise pressure, the predictable, mechanically timed hypertension that accompanies clamping is explained by afterload, not by anesthetic depth."},{"text":"Renin-angiotensin activation producing immediate angiotensin II vasoconstriction","label":"D","correct":false,"rationale":"Incorrect: renin-angiotensin activation contributes to later humoral effects but operates over minutes and is not the immediate mechanism of the instantaneous pressure rise."},{"text":"An acute increase in left ventricular afterload from the rise in systemic vascular resistance","label":"E","correct":true,"rationale":"Correct: occluding the aorta abruptly raises impedance to ejection, increasing systemic vascular resistance and afterload, which is the principal driver of the hypertension that follows cross-clamping."}]'::jsonb, 'E', 'Aortic cross-clamping abruptly increases impedance to left ventricular ejection, raising systemic vascular resistance and afterload; this mechanical change is the dominant cause of the hypertension seen immediately after the clamp is applied. Blood volume also redistributes proximally, raising preload, and the magnitude depends on clamp level (greater with supraceliac than infraceliac). Humoral effects such as renin-angiotensin activation and catecholamine release evolve over the following minutes, and ischemic metabolite washout produces the hypotension characteristic of unclamping.', '[{"url":"https://www.openanesthesia.org/keywords/aortic-cross-clamping/","source":"Aortic Cross-Clamping - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-006', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'Carotid endarterectomy: cerebral oximetry/NIRS neuromonitoring', 'hard', 'A 68-year-old woman with hypertension and a 90% left internal carotid stenosis undergoes carotid endarterectomy under general anesthesia. Cerebral regional oxygen saturation is monitored bilaterally with near-infrared spectroscopy (NIRS). Baseline left-sided rSO2 is 68%. Shortly after the surgeon applies the carotid cross-clamp, the left rSO2 falls to 55% while the right side and all other vital signs, including mean arterial pressure of 82 mmHg and normocapnia, remain unchanged. Which response is the most appropriate next step?', '[{"text":"Communicate the ipsilateral desaturation to the surgeon and support placement of an intraluminal shunt while raising the blood pressure","label":"A","correct":true,"rationale":"Correct: an isolated ipsilateral NIRS decline after clamping signals inadequate collateral perfusion, and the appropriate response is to alert the surgeon for possible shunt placement while augmenting blood pressure to improve collateral flow."},{"text":"Continue observation, because a drop of this magnitude is within normal variation and does not indicate ischemia","label":"B","correct":false,"rationale":"Incorrect: a relative decline of roughly 19% from baseline approaches the threshold associated with cerebral ischemia and warrants action rather than passive observation."},{"text":"Lower the mean arterial pressure to reduce embolic risk across the operative field","label":"C","correct":false,"rationale":"Incorrect: deliberately lowering pressure would further reduce collateral cerebral perfusion through the circle of Willis and worsen the ipsilateral desaturation."},{"text":"Deepen anesthesia with additional volatile agent to lower cerebral metabolic demand","label":"D","correct":false,"rationale":"Incorrect: while reducing metabolic rate has theoretical appeal, volatile agents cause vasodilation and hypotension that can compromise collateral flow, and this does not address the perfusion deficit as directly as restoring flow."},{"text":"Increase the FiO2 to 1.0 to raise arterial oxygen content","label":"E","correct":false,"rationale":"Incorrect: arterial oxygenation is already adequate and raising FiO2 does little for a regional saturation drop caused by reduced perfusion rather than reduced arterial oxygen content."}]'::jsonb, 'A', 'During carotid endarterectomy, an isolated ipsilateral fall in NIRS cerebral oximetry after cross-clamping reflects inadequate collateral perfusion through the circle of Willis, and a relative decline near 20% from baseline is the reported threshold linked to acute cerebral ischemia. The correct response is to communicate with the surgeon to support shunt placement and to augment collateral flow by raising blood pressure toward or above baseline, not to lower pressure or simply observe. NIRS is one of several monitors (alongside EEG, evoked potentials, and awake neurologic exam) used to detect clamp-related ischemia.', '[{"url":"https://www.openanesthesia.org/keywords/cerebral-oximetry-and-near-infrared-spectroscopy/","source":"Cerebral Oximetry and Near Infrared Spectroscopy - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-007', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Pharmacokinetics: context-sensitive half-time of intravenous infusions', 'medium', 'A 78-year-old man (110 kg, BMI 38) with obstructive sleep apnea, an EF of 35%, and chronic kidney disease (eGFR 28 mL/min) undergoes a 6-hour open abdominal aortic aneurysm repair. Anesthesia is maintained with a propofol infusion plus a continuous remifentanil infusion at 0.2 mcg/kg/min. The surgeon places the final fascial suture and the team plans an awake, extubated emergence. The remifentanil infusion is discontinued. Compared with discontinuing a fentanyl infusion that had run for the same duration, what is the expected behavior of the plasma remifentanil concentration after the infusion is stopped?', '[{"text":"It will decline slowly because hepatic clearance of remifentanil is markedly reduced by the patient''s low cardiac output","label":"A","correct":false,"rationale":"Incorrect: remifentanil clearance depends on widespread ester hydrolysis rather than hepatic blood flow, so a low ejection fraction does not meaningfully prolong its offset."},{"text":"It will decrease rapidly with a context-sensitive half-time of roughly 3-4 minutes, essentially independent of infusion duration","label":"B","correct":true,"rationale":"Correct: remifentanil is cleared by nonspecific plasma and tissue esterases, so it does not accumulate and its context-sensitive half-time stays near 3-4 minutes regardless of how long it was infused."},{"text":"It will be prolonged relative to fentanyl because the patient''s renal impairment causes accumulation of remifentanil","label":"C","correct":false,"rationale":"Incorrect: although the carboxylic acid metabolite is renally excreted and accumulates, it is essentially inactive, so renal failure does not prolong remifentanil''s clinical offset."},{"text":"It will mirror fentanyl, since both opioids have a context-sensitive half-time that lengthens substantially with longer infusions","label":"D","correct":false,"rationale":"Incorrect: fentanyl''s context-sensitive half-time lengthens markedly with infusion duration because of peripheral tissue accumulation, whereas remifentanil''s does not."},{"text":"It will decrease faster than fentanyl only if naloxone is co-administered to displace it from peripheral compartments","label":"E","correct":false,"rationale":"Incorrect: remifentanil''s rapid offset is intrinsic to its esterase metabolism and requires no antagonist, and naloxone would not change its pharmacokinetics."}]'::jsonb, 'B', 'Context-sensitive half-time is the time for plasma drug concentration to fall by 50% after stopping a continuous infusion, and it depends on both the duration of infusion and the drug''s distribution and clearance. Remifentanil is metabolized by nonspecific plasma and tissue esterases, so it does not accumulate in peripheral tissues and its context-sensitive half-time remains roughly 3-4 minutes even after prolonged infusions. This duration-independent, organ-independent offset makes it predictable in patients with hepatic, renal, or cardiac compromise, in contrast to fentanyl, whose context-sensitive half-time grows substantially with longer infusions.', '[{"url":"https://www.openanesthesia.org/keywords/context-sensitive-half-time/","source":"Context-Sensitive Half-Time (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-008', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Local anesthetics: systemic toxicity (LAST) and lipid emulsion rescue', 'easy', 'A 24-year-old woman (60 kg) is having an ultrasound-guided interscalene brachial plexus block placed for shoulder arthroscopy. Approximately two minutes after injection of 30 mL of 0.5% bupivacaine, she reports perioral numbness and tinnitus, then becomes agitated and has a generalized tonic-clonic seizure followed by bradycardia and a widened QRS on the monitor. The seizure is terminated with midazolam and the airway is secured. After calling for help and the lipid emulsion kit, which intervention is the most important specific therapy for this patient''s condition?', '[{"text":"Administer a high-dose epinephrine bolus of 1 mg IV per standard ACLS dosing","label":"A","correct":false,"rationale":"Incorrect: in local anesthetic systemic toxicity, large epinephrine boluses can worsen arrhythmias and impair resuscitation, so reduced doses (≤ 1 mcg/kg) are recommended."},{"text":"Administer intralipid only if cardiac arrest occurs, withholding it while a pulse is present","label":"B","correct":false,"rationale":"Incorrect: lipid emulsion should be started at the first sign of serious toxicity such as seizures or cardiovascular instability, not delayed until arrest."},{"text":"Give a 20% lipid emulsion bolus of approximately 1.5 mL/kg over 1 minute, then start an infusion","label":"C","correct":true,"rationale":"Correct: 20% lipid emulsion is the specific antidote for local anesthetic systemic toxicity, dosed as a 1.5 mL/kg bolus followed by an infusion to create a lipid sink and support cardiac energetics."},{"text":"Give intravenous flumazenil to reverse the midazolam and clarify the cause of the seizure","label":"D","correct":false,"rationale":"Incorrect: flumazenil does not treat local anesthetic toxicity and could lower the seizure threshold further in a patient already convulsing from bupivacaine."},{"text":"Administer a calcium chloride bolus to stabilize the myocardium against the widened QRS","label":"E","correct":false,"rationale":"Incorrect: calcium does not reverse bupivacaine-induced sodium channel blockade and is not part of the local anesthetic systemic toxicity protocol."}]'::jsonb, 'C', 'Local anesthetic systemic toxicity (LAST) classically progresses from neurologic excitation (perioral numbness, tinnitus, agitation, seizures) to cardiovascular collapse, and bupivacaine is particularly cardiotoxic because of its avid, slow-dissociating sodium channel blockade. Twenty percent lipid emulsion is the specific therapy: a bolus of about 1.5 mL/kg lean body weight over 1 minute followed by an infusion of roughly 0.25 mL/kg/min. Lipid should be given early at the first signs of serious toxicity, alongside airway management, seizure control, and modified ACLS using reduced epinephrine doses and avoidance of vasopressin, calcium channel blockers, and local anesthetic antiarrhythmics.', '[{"url":"https://www.openanesthesia.org/keywords/local-anesthetic-systemic-toxicity/","source":"Local Anesthetic Systemic Toxicity (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-009', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Inhalational and neuromuscular agents: malignant hyperthermia and dantrolene', 'medium', 'A previously healthy 19-year-old man undergoes general anesthesia for an open reduction of a tibial fracture. Anesthesia is induced with propofol and rocuronium and maintained with sevoflurane. About 40 minutes into the case the anesthesia care team notes an unexplained rise in end-tidal CO2 to 68 mmHg despite increased minute ventilation, sinus tachycardia, generalized muscle rigidity, and a temperature climbing from 37.2°C to 39.8°C. Malignant hyperthermia is suspected. After discontinuing the volatile agent, hyperventilating with 100% oxygen, and converting to a nontriggering technique, what is the most important specific pharmacologic treatment?', '[{"text":"Give a beta-blocker such as esmolol to control the tachycardia and reduce metabolic demand","label":"A","correct":false,"rationale":"Incorrect: a beta-blocker treats only the heart rate and does not address the underlying skeletal muscle hypermetabolism that defines the crisis."},{"text":"Administer a benzodiazepine infusion to relax the rigid skeletal muscles","label":"B","correct":false,"rationale":"Incorrect: benzodiazepines act centrally and cannot reverse the ryanodine-receptor-mediated calcium release responsible for the sustained muscle rigidity."},{"text":"Give an additional dose of a nondepolarizing neuromuscular blocker to abolish the rigidity","label":"C","correct":false,"rationale":"Incorrect: the rigidity arises from intracellular calcium dysregulation distal to the neuromuscular junction, so neuromuscular blockers do not relieve it."},{"text":"Administer intravenous dantrolene 2.5 mg/kg, repeated as needed until signs of hypermetabolism resolve","label":"D","correct":true,"rationale":"Correct: dantrolene is the only specific treatment for malignant hyperthermia, started at 2.5 mg/kg IV and repeated until end-tidal CO2, rigidity, and temperature improve, because it blocks pathologic calcium release from the ryanodine receptor."},{"text":"Administer sodium bicarbonate as the primary therapy to correct the metabolic acidosis","label":"E","correct":false,"rationale":"Incorrect: bicarbonate is supportive for severe acidosis but does not treat the cause, and without dantrolene the hypermetabolism continues."}]'::jsonb, 'D', 'Malignant hyperthermia is a syndrome of skeletal muscle hypermetabolism triggered by volatile anesthetics and succinylcholine in genetically susceptible patients, usually from a ryanodine receptor (RYR1) mutation. Early signs include an unexplained rise in end-tidal CO2, tachycardia, masseter or generalized rigidity, and a later rise in temperature. Management is to stop triggering agents, hyperventilate with 100% oxygen, and give dantrolene 2.5 mg/kg IV repeated until the hypermetabolic signs abate, while treating hyperkalemia, acidosis, and arrhythmias and cooling the patient.', '[{"url":"https://www.openanesthesia.org/keywords/malignant-hyperthermia/","source":"Malignant Hyperthermia (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-010', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Operating room / airway fire during laser airway surgery', 'medium', 'A 58-year-old man with early glottic squamous cell carcinoma is undergoing CO2 laser excision of a vocal cord lesion under general anesthesia via a laser-resistant endotracheal tube. During the case, the surgeon activates the laser and a flash with flame is immediately seen at the surgical field within the airway. Which of the following is the MOST appropriate FIRST action?', '[{"text":"Disconnect the breathing circuit but leave the tube in place to protect the airway","label":"A","correct":false,"rationale":"Incorrect: leaving the ignited tube in place allows it to continue burning and injuring the airway, so it must be removed, not retained."},{"text":"Reduce the FiO2 to 0.30 and continue the case once the flame self-extinguishes","label":"B","correct":false,"rationale":"Incorrect: merely lowering FiO2 does not address the actively burning tube and delays the definitive step of stopping gas flow and removing it."},{"text":"Flood the surgical field with saline before addressing the breathing circuit","label":"C","correct":false,"rationale":"Incorrect: pouring saline is a useful adjunct after the tube is removed, but stopping gas flow and removing the tube must come first to halt the fire."},{"text":"Administer a bolus of intravenous dexamethasone and racemic epinephrine","label":"D","correct":false,"rationale":"Incorrect: steroids and nebulized epinephrine address later airway edema but do nothing to extinguish an active fire that is causing ongoing thermal injury."},{"text":"Stop the flow of all airway gases and remove the endotracheal tube","label":"E","correct":true,"rationale":"Correct: the first priority in an airway fire is to immediately stop ventilation (cut off the oxidizer) and remove the burning endotracheal tube, which is both fuel and a conduit for the fire."}]'::jsonb, 'E', 'In an airway fire, the immediate response is to simultaneously stop the flow of airway gases (removing the oxidizer) and remove the endotracheal tube (removing the fuel and ignition conduit); only then is the field flooded with saline and the airway re-evaluated. Prevention centers on using the lowest feasible FiO2, avoiding nitrous oxide, and using a laser-resistant tube with a saline-filled cuff. After extinguishing the fire, the patient should be re-intubated, the airway inspected via bronchoscopy for thermal injury, and supportive care provided.', '[{"url":"https://www.openanesthesia.org/keywords/surgical-fires/","source":"Surgical Fires - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-011', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Pediatric ENT emergency / post-tonsillectomy hemorrhage', 'medium', 'A 4-year-old, 18-kg girl is brought to the operating room 7 hours after adenotonsillectomy with active bleeding from the tonsillar fossa. She has swallowed blood, is tachycardic at 150/min, has cool extremities and capillary refill of 3 seconds, and is anxious. Hemoglobin is 9.1 g/dL. The surgeon plans urgent control of the bleeding. Which of the following is the MOST appropriate anesthetic approach?', '[{"text":"Volume resuscitation followed by rapid sequence induction with a styletted tube and suction ready","label":"A","correct":true,"rationale":"Correct: the child is hypovolemic with a stomach full of blood, so isotonic fluid resuscitation before a rapid sequence induction with two working suctions and a styletted tube optimizes hemodynamics and protects against aspiration."},{"text":"Inhalational induction with sevoflurane while maintaining spontaneous ventilation","label":"B","correct":false,"rationale":"Incorrect: a slow inhalational induction in a hypovolemic child with a full stomach of blood markedly increases aspiration risk and risks hemodynamic collapse from vasodilation."},{"text":"Awake fiberoptic intubation under topical anesthesia","label":"C","correct":false,"rationale":"Incorrect: awake fiberoptic intubation is impractical and poorly tolerated in a frightened young child with active oropharyngeal bleeding that obscures the view."},{"text":"Proceed immediately with induction without intravenous access, placing an IV after the airway is secured","label":"D","correct":false,"rationale":"Incorrect: inducing a hypovolemic, actively bleeding child without IV access removes the ability to resuscitate or treat hypotension during a high-risk induction."},{"text":"Deep extubation at the end of the case to avoid coughing and re-bleeding","label":"E","correct":false,"rationale":"Incorrect: this child is at high aspiration risk from swallowed blood, so she should be fully awake with protective reflexes before extubation, not extubated deep."}]'::jsonb, 'A', 'A child with post-tonsillectomy hemorrhage is often hypovolemic, anemic, and has a stomach full of swallowed blood, creating combined risks of hemodynamic instability and aspiration. Management priorities are establishing IV access, resuscitating with 10-20 mL/kg isotonic crystalloid, preparing two suctions and multiple laryngoscopy tools, and performing a rapid sequence induction. Because of the aspiration risk, the trachea should be extubated only when the child is fully awake with intact airway reflexes.', '[{"url":"https://www.openanesthesia.org/keywords/posttonsillectomy-hemorrhage/","source":"Posttonsillectomy Hemorrhage - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-012', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Deep neck space infection / difficult airway (Ludwig angina)', 'hard', 'A 52-year-old man with poorly controlled diabetes presents with a 2-day history of a swollen, tender, indurated submandibular region, trismus, drooling, a muffled "hot potato" voice, and an elevated, displaced tongue after a recent dental infection. He is sitting upright, leaning forward, with mild stridor and an oxygen saturation of 93% on room air. He requires general anesthesia for incision and drainage. Which of the following is the MOST appropriate plan for securing the airway?', '[{"text":"Standard intravenous rapid sequence induction with rocuronium and direct laryngoscopy","label":"A","correct":false,"rationale":"Incorrect: inducing apnea and paralysis in a patient with severe floor-of-mouth edema and trismus risks complete airway loss with an unintubatable, unmaskable airway."},{"text":"Awake fiberoptic intubation with topicalization and a surgeon prepared for emergency tracheostomy","label":"B","correct":true,"rationale":"Correct: maintaining spontaneous ventilation via awake fiberoptic intubation while preserving the patient''s own airway tone, with surgical airway backup immediately available, is the safest approach in Ludwig angina."},{"text":"Inhalational induction with sevoflurane followed by direct laryngoscopy once deep","label":"C","correct":false,"rationale":"Incorrect: inhalational induction is unreliable in a distorted, swollen airway and can precipitate total obstruction once muscle tone is lost."},{"text":"Placement of a supraglottic airway device after a small dose of propofol","label":"D","correct":false,"rationale":"Incorrect: a supraglottic device cannot bypass supraglottic and floor-of-mouth swelling and does not protect against the rapidly progressive obstruction of Ludwig angina."},{"text":"Blind nasotracheal intubation without sedation","label":"E","correct":false,"rationale":"Incorrect: blind nasotracheal intubation in a distorted, edematous airway is likely to fail, cause bleeding, and worsen obstruction."}]'::jsonb, 'B', 'This patient has Ludwig angina, a rapidly progressive cellulitis of the submandibular, sublingual, and submental spaces that distorts the floor of the mouth and elevates the tongue, producing a potentially catastrophic difficult airway. The safest strategy preserves spontaneous ventilation through an awake technique such as awake fiberoptic intubation, with a surgeon scrubbed and ready for emergency tracheostomy. Induction of apnea or paralysis before the airway is secured risks a ''cannot intubate, cannot ventilate'' scenario.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK482354/","source":"Ludwig Angina - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-013', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Pheochromocytoma resection - preoperative adrenergic blockade sequencing', 'medium', 'A 44-year-old woman with episodic headaches, palpitations, and diaphoresis is found to have markedly elevated plasma free metanephrines and a 4-cm right adrenal mass consistent with pheochromocytoma. She is scheduled for laparoscopic adrenalectomy in 3 weeks. Her clinic blood pressure is 168/104 mmHg and heart rate is 96 beats/min. The surgical team asks how to begin pharmacologic optimization before the operation. Which approach is most appropriate to start her preoperative preparation?', '[{"text":"Begin metoprolol now to control her resting tachycardia, then add an alpha-blocker closer to surgery","label":"A","correct":false,"rationale":"Starting a beta-blocker first leaves alpha-mediated vasoconstriction unopposed, which can precipitate a severe hypertensive crisis and is explicitly contraindicated as the initial step."},{"text":"Start a calcium channel blocker as monotherapy and avoid alpha-blockade entirely to preserve intraoperative blood pressure lability","label":"B","correct":false,"rationale":"Calcium channel blockers are useful adjuncts or alternatives in selected patients, but routine preparation centers on alpha-blockade; relying on a calcium channel blocker alone is not the standard primary strategy and does not adequately control catecholamine-driven vasoconstriction."},{"text":"Start an alpha-adrenergic blocker such as phenoxybenzamine 10 to 14 days before surgery, adding a beta-blocker only after adequate alpha-blockade is established","label":"C","correct":true,"rationale":"Alpha-blockade begun roughly 10 to 14 days preoperatively controls vasoconstriction and allows intravascular volume to re-expand, and a beta-blocker is added only afterward to manage reflex tachycardia, making this the correct sequence."},{"text":"Proceed directly to surgery without medical preparation because laparoscopic resection minimizes catecholamine release","label":"D","correct":false,"rationale":"Tumor manipulation during any resection, including laparoscopic, can release massive catecholamine surges, so omitting preoperative blockade markedly increases the risk of intraoperative hypertensive crisis and is unacceptable."},{"text":"Restrict sodium and fluids in the days before surgery to blunt the expected intraoperative hypertension","label":"E","correct":false,"rationale":"These patients are chronically volume-contracted from catecholamine excess; fluid and sodium liberalization after alpha-blockade is encouraged, whereas restriction worsens the post-resection hypotension seen once catecholamine levels fall."}]'::jsonb, 'C', 'Catecholamine excess in pheochromocytoma produces chronic vasoconstriction and intravascular volume depletion. Alpha-adrenergic blockade started about 10 to 14 days preoperatively (classically phenoxybenzamine) relaxes the vasculature and allows the contracted plasma volume to re-expand, and only after this is achieved is a beta-blocker added to control reflex or residual tachycardia. Initiating beta-blockade first removes beta-2 mediated vasodilation while leaving alpha-mediated vasoconstriction unopposed, which can trigger a hypertensive crisis and acute heart failure. Adequate preparation, often confirmed by liberalized salt and fluid intake, blunts both the intraoperative catecholamine surge during tumor manipulation and the hypotension that follows ligation of the tumor''s venous drainage.', '[{"url":"https://www.openanesthesia.org/keywords/pheochromocytoma/","source":"Pheochromocytoma - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-014', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Diabetic ketoacidosis - perioperative electrolyte management before insulin', 'hard', 'A 22-year-old man with type 1 diabetes presents with a perforated appendix requiring urgent appendectomy. He is lethargic and breathing deeply. Labs show glucose 540 mg/dL, arterial pH 7.18, bicarbonate 9 mEq/L, an elevated anion gap with positive serum ketones, and serum potassium 3.1 mEq/L. The team is initiating treatment for diabetic ketoacidosis while preparing him for surgery. After starting aggressive isotonic crystalloid resuscitation, what is the most appropriate next step regarding insulin and potassium?', '[{"text":"Give an immediate IV insulin bolus and start an insulin infusion to rapidly close the anion gap, then replace potassium once it falls further","label":"A","correct":false,"rationale":"Insulin drives potassium intracellularly, so starting insulin while the serum potassium is already 3.1 mEq/L can precipitate life-threatening hypokalemia and arrhythmias, making this the dangerous wrong choice."},{"text":"Administer IV sodium bicarbonate to correct the acidosis first, which will raise the potassium and allow safe insulin dosing","label":"B","correct":false,"rationale":"Bicarbonate actually shifts potassium intracellularly and lowers serum potassium further, and it is not indicated at this pH, so it would worsen rather than solve the problem."},{"text":"Start the insulin infusion together with a dextrose-containing fluid now to prevent hypoglycemia, deferring potassium until later","label":"C","correct":false,"rationale":"Dextrose is added only once glucose falls to about 200 to 250 mg/dL, and starting insulin with this markedly low potassium still risks dangerous hypokalemia regardless of the dextrose."},{"text":"Withhold insulin and begin IV potassium replacement until the serum potassium exceeds 3.3 mEq/L, then start the insulin infusion","label":"D","correct":true,"rationale":"Because total body potassium is depleted in DKA and insulin shifts potassium into cells, insulin is held until the serum potassium is corrected above 3.3 mEq/L, after which the infusion can be safely started."},{"text":"Proceed to induction of general anesthesia immediately and manage the DKA entirely intraoperatively, since source control is the priority","label":"E","correct":false,"rationale":"When time allows, even with urgent surgery, initial resuscitation and correction of dangerous electrolyte and acid-base derangements should begin preoperatively because uncorrected hypokalemia and acidosis greatly increase the risk of intraoperative arrhythmias and instability."}]'::jsonb, 'D', 'In diabetic ketoacidosis, total body potassium is depleted even when the measured serum level appears normal or low, because acidosis and insulin deficiency shift potassium out of cells. Insulin reverses this shift and drives potassium intracellularly, so giving insulin when the serum potassium is already low (here 3.1 mEq/L) can cause profound hypokalemia and fatal arrhythmias. Standard practice is therefore to hold insulin and replace potassium until the serum level is at least 3.3 mEq/L, while aggressive isotonic fluid resuscitation continues; dextrose is added to the fluids only once glucose falls to roughly 200 to 250 mg/dL. For a patient needing urgent surgery, these derangements should be addressed before induction whenever the clinical timeline permits.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK534848/","source":"Ketoacidosis - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-015', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Thyroid storm - intraoperative recognition and treatment', 'medium', 'A 35-year-old woman with poorly controlled Graves disease undergoes emergency open reduction of an ankle fracture under general anesthesia, having had no time for medical optimization. Roughly 45 minutes into the case she develops a temperature of 40.1 C, heart rate of 165 beats/min in sinus tachycardia, blood pressure of 95/50 mmHg, and copious diaphoresis. End-tidal CO2 is mildly elevated but stable, and there is no masseter rigidity, no generalized muscular rigidity, and no rapid rise in end-tidal CO2. Which intervention most directly targets the underlying disorder?', '[{"text":"Administer dantrolene 2.5 mg/kg IV and discontinue all volatile anesthetic, treating this as malignant hyperthermia","label":"A","correct":false,"rationale":"The absence of rigidity, lack of an unexplained rapid rise in end-tidal CO2, and the clinical context of untreated Graves disease point away from malignant hyperthermia, so dantrolene does not target the actual disorder."},{"text":"Give a bolus of IV phenylephrine to support blood pressure and deepen anesthesia, then continue the case unchanged","label":"B","correct":false,"rationale":"This addresses only the hypotension and ignores the life-threatening thyrotoxic crisis, failing to treat the underlying catecholamine-sensitive hyperthyroid state."},{"text":"Treat with active surface cooling alone and defer pharmacologic therapy until thyroid function tests confirm the diagnosis","label":"C","correct":false,"rationale":"Thyroid storm is a clinical diagnosis requiring immediate treatment; waiting for confirmatory labs and using cooling alone delays the specific therapy needed to prevent death."},{"text":"Administer IV calcium chloride and sodium bicarbonate empirically to treat presumed hyperkalemic crisis","label":"D","correct":false,"rationale":"There is no evidence of hyperkalemia in this scenario, and this regimen does not address the thyrotoxic state that is driving the hyperthermia and tachycardia."},{"text":"Administer IV esmolol (or propranolol) to control the adrenergic response, give a thionamide such as propylthiouracil, and provide active cooling and supportive care","label":"E","correct":true,"rationale":"Beta-blockade blunts the dangerous adrenergic and hyperdynamic state, a thionamide blocks new thyroid hormone synthesis, and cooling plus supportive care round out the standard treatment of thyroid storm, directly targeting the disorder."}]'::jsonb, 'E', 'Intraoperative thyroid storm classically presents with marked hyperthermia, severe tachycardia, and hemodynamic changes in a patient with untreated or poorly controlled hyperthyroidism subjected to a stressor such as surgery, and it can mimic malignant hyperthermia. Key distinguishing features are the absence of muscular rigidity and the lack of a rapid, unexplained rise in end-tidal CO2 and severe acidosis that characterize malignant hyperthermia, along with the relevant endocrine history. Treatment is directed at the pathophysiology: a beta-blocker (esmolol or propranolol) to control the adrenergic surge, a thionamide such as propylthiouracil or methimazole to halt new hormone synthesis, and aggressive cooling with supportive care; iodine and corticosteroids are added in the full regimen. Dantrolene is reserved for true malignant hyperthermia and does not treat thyrotoxicosis.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK448095/","source":"Thyroid Storm - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-016', 'Ophthalmic', 'Ophthalmic', 'Subspecialty Care', 'Oculocardiac reflex during strabismus surgery', 'easy', 'A 4-year-old, 16-kg child is undergoing bilateral medial rectus recession for strabismus under general anesthesia with sevoflurane and a laryngeal mask airway, breathing spontaneously. The case is maintained without an anticholinergic. As the surgeon places traction on the right medial rectus muscle, the heart rate abruptly falls from 110 to 48 beats/min with frequent premature ventricular complexes; blood pressure is 78/45 mmHg and SpO2 is 99%. What is the most appropriate IMMEDIATE next step?', '[{"text":"Ask the surgeon to release traction on the extraocular muscle","label":"A","correct":true,"rationale":"Correct: removing the triggering stimulus is the first-line maneuver and usually resolves the oculocardiac reflex within seconds before pharmacologic intervention is needed."},{"text":"Administer IV atropine 0.02 mg/kg immediately","label":"B","correct":false,"rationale":"Incorrect as the first action: an anticholinergic is given for persistent or recurrent bradycardia after the stimulus is removed, not before releasing traction."},{"text":"Give a 20 mL/kg crystalloid bolus to raise the heart rate","label":"C","correct":false,"rationale":"Incorrect: this bradycardia is vagally mediated from muscle traction, not hypovolemia, so fluid will not abolish the reflex."},{"text":"Deepen anesthesia with a propofol bolus","label":"D","correct":false,"rationale":"Incorrect: deepening anesthesia (especially with TIVA) does not blunt and may even increase oculocardiac reflex incidence, and would worsen the hypotension."},{"text":"Begin chest compressions and call for the code cart","label":"E","correct":false,"rationale":"Incorrect: the patient has a perfusing rhythm with adequate blood pressure and oxygenation, so compressions are not indicated."}]'::jsonb, 'A', 'The oculocardiac (trigeminovagal) reflex is triggered by traction on the extraocular muscles or pressure on the globe, with the trigeminal nerve as the afferent and the vagus as the efferent limb. Strabismus surgery and medial rectus traction in children are classic provocations. The reflex is fatigable, so the immediate step is to ask the surgeon to release the stimulus, which usually restores the rhythm within seconds; atropine or glycopyrrolate is reserved for persistent or recurrent bradycardia.', '[{"url":"https://www.openanesthesia.org/keywords/oculocardiac-reflex/","source":"Oculocardiac Reflex - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-017', 'Ophthalmic', 'Ophthalmic', 'Subspecialty Care', 'Nitrous oxide interaction with intraocular gas tamponade', 'hard', 'A 63-year-old woman returns to the operating room for an unrelated incarcerated hernia repair 5 days after pars plana vitrectomy with intravitreal sulfur hexafluoride (SF6) gas tamponade for a macular hole; she has been instructed to position face-down. The anesthesiologist assistant is planning a general anesthetic. Which intraoperative decision is MOST important to prevent catastrophic vision loss in the operated eye?', '[{"text":"Administer nitrous oxide but limit the concentration to 50%","label":"A","correct":false,"rationale":"Incorrect: even sub-anesthetic nitrous oxide concentrations cause clinically significant bubble expansion and intraocular pressure spikes; no concentration is considered safe with an intraocular gas bubble."},{"text":"Avoid nitrous oxide and maintain anesthesia with an air/oxygen and volatile or total intravenous technique","label":"B","correct":true,"rationale":"Correct: nitrous oxide diffuses into the SF6 bubble faster than nitrogen leaves, expanding the bubble, raising intraocular pressure, and threatening retinal perfusion, so it must be avoided until the gas resorbs."},{"text":"Avoid all volatile anesthetics because they raise intraocular pressure","label":"C","correct":false,"rationale":"Incorrect: volatile agents actually lower intraocular pressure and are acceptable; the agent that must be avoided is nitrous oxide."},{"text":"Keep the patient supine rather than face-down to reduce ocular pressure","label":"D","correct":false,"rationale":"Incorrect: positioning is dictated by the retinal surgeon and does not address the gas-expansion mechanism, which is driven by nitrous oxide diffusion."},{"text":"Limit peak airway pressures to below 20 cmH2O to protect the globe","label":"E","correct":false,"rationale":"Incorrect: airway pressure does not meaningfully affect an intravitreal gas bubble, whereas nitrous oxide exposure directly expands it."}]'::jsonb, 'B', 'An intravitreal SF6 bubble can persist for up to several weeks and C3F8 for up to two months. Because nitrous oxide is far more soluble in blood than the inert fluorinated gas, it enters the closed bubble faster than the gas diffuses out, causing rapid expansion, a dangerous rise in intraocular pressure, compromised retinal arterial perfusion, and potentially irreversible blindness. Nitrous oxide must be withheld in any patient with intraocular gas until the bubble has fully resorbed, and patients are typically issued a warning bracelet for this reason.', '[{"url":"https://www.openanesthesia.org/keywords/nitrous-oxide/","source":"Nitrous Oxide - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-018', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Fluid, electrolyte, and acid-base management (hypertrophic pyloric stenosis)', 'medium', 'A 5-week-old, 4.2 kg former full-term male presents for pyloromyotomy after a 10-day history of progressive nonbilious projectile vomiting. He appears lethargic with dry mucous membranes and sunken fontanelle. Laboratory studies show: sodium 134 mEq/L, potassium 2.9 mEq/L, chloride 88 mEq/L, bicarbonate 36 mEq/L, and pH 7.52. The surgeon asks to proceed to the operating room immediately. What is the most appropriate next step in management?', '[{"text":"Proceed immediately with a rapid sequence induction because the dehydration increases aspiration risk","label":"A","correct":false,"rationale":"Incorrect: although aspiration risk is real and a rapid sequence (or modified) induction with gastric suctioning is used, surgery should not proceed until the metabolic alkalosis and hypokalemia are corrected."},{"text":"Administer intravenous acetazolamide to correct the metabolic alkalosis before induction","label":"B","correct":false,"rationale":"Incorrect: the alkalosis is chloride-responsive and resolves with saline and potassium repletion, so a carbonic anhydrase inhibitor is unnecessary and may worsen volume and potassium status."},{"text":"Delay surgery to administer 0.9% sodium chloride with potassium supplementation and correct the electrolyte and acid-base derangements","label":"C","correct":true,"rationale":"Correct: pyloric stenosis is a medical, not a surgical, emergency, and the hypochloremic, hypokalemic metabolic alkalosis with dehydration must be corrected before anesthesia to avoid postoperative apnea and arrhythmia."},{"text":"Give a bolus of 0.45% sodium chloride in 5% dextrose to rapidly restore free water before surgery","label":"D","correct":false,"rationale":"Incorrect: hypotonic fluid is inappropriate for resuscitation here because chloride repletion with isotonic saline is required to reverse the alkalosis and the contraction of extracellular volume."},{"text":"Proceed with an inhalational induction using sevoflurane and spontaneous ventilation given the infant''s small size","label":"E","correct":false,"rationale":"Incorrect: a full or partially obstructed stomach mandates airway protection rather than spontaneous ventilation, and surgery should still be deferred until metabolic correction is achieved."}]'::jsonb, 'C', 'Hypertrophic pyloric stenosis produces a hypochloremic, hypokalemic metabolic alkalosis from loss of gastric hydrogen and chloride, with secondary hypovolemia. Because the unresolved alkalosis blunts central respiratory drive (via slow-equilibrating CSF pH) and hypokalemia predisposes to arrhythmia, the condition must be medically optimized before induction. Targets generally include serum chloride above 100 mEq/L, bicarbonate below 30 mEq/L, and adequate urine output before proceeding.', '[{"url":"https://www.openanesthesia.org/keywords/pyloric-stenosis/","source":"Pyloric Stenosis"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-019', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Airway emergencies (laryngospasm management)', 'easy', 'A previously healthy 3-year-old, 15 kg child undergoing adenotonsillectomy is extubated awake at the end of the case. Within seconds the child develops complete airway obstruction with paradoxical chest movement, tracheal tug, and no air movement despite a tight mask seal. SpO2 falls from 99% to 84%. Jaw thrust, removal of oral secretions, and 100% oxygen with continuous positive airway pressure fail to break the obstruction. An intravenous line is patent. Which of the following is the most appropriate next intervention?', '[{"text":"Deepen anesthesia with an additional dose of inhaled sevoflurane via the obstructed airway","label":"A","correct":false,"rationale":"Incorrect: with complete obstruction there is no gas exchange, so delivering volatile agent across the closed cords is ineffective and wastes critical time."},{"text":"Perform immediate needle cricothyroidotomy to establish a surgical airway","label":"B","correct":false,"rationale":"Incorrect: a front-of-neck airway is reserved for a true ''cannot intubate, cannot oxygenate'' situation after pharmacologic measures fail, not as the first response to laryngospasm with IV access available."},{"text":"Reintubate the trachea immediately without administering any medication","label":"C","correct":false,"rationale":"Incorrect: attempting to force a tube through tightly apposed cords is likely to fail and traumatize the larynx, whereas pharmacologic relaxation first makes intubation unnecessary or far easier."},{"text":"Administer intravenous succinylcholine to relax the laryngeal musculature","label":"D","correct":true,"rationale":"Correct: when positive-pressure maneuvers fail to break laryngospasm and desaturation is progressing, a small dose of intravenous succinylcholine rapidly relaxes the cords and is the definitive step."},{"text":"Administer intravenous atropine to reduce vagally mediated airway reactivity","label":"E","correct":false,"rationale":"Incorrect: atropine is useful to treat or prevent the bradycardia that may accompany hypoxia or succinylcholine, but it does not relieve the laryngospasm itself."}]'::jsonb, 'D', 'Laryngospasm is a sustained glottic closure reflex most common at extubation in children and after airway surgery. First-line management is removal of the stimulus, jaw thrust with firm pressure at the laryngospasm notch (Larson''s maneuver), and CPAP with 100% oxygen. When these fail and oxygen saturation is falling, intravenous succinylcholine (with atropine to prevent bradycardia) is the definitive treatment; if no IV is present, an intramuscular dose can be given.', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-020', 'Pediatric', 'Pediatric', 'Subspecialty Care', 'Postoperative complications (emergence delirium)', 'medium', 'A 4-year-old, 17 kg child with no significant medical history undergoes bilateral myringotomy and tube placement under sevoflurane by mask. In the recovery area, shortly after awakening, the child is inconsolably thrashing, does not make eye contact, does not recognize the parents, and cannot be comforted. Vital signs are stable, SpO2 is 99% on room air, the surgical site is dry, and a focused exam reveals no signs of airway obstruction or bladder distention. A nurse asks how to manage the agitation. Which of the following is the most likely diagnosis and appropriate management?', '[{"text":"Postoperative pain; treat with an additional dose of intravenous opioid","label":"A","correct":false,"rationale":"Incorrect: myringotomy is minimally painful and the child shows non-purposeful agitation without recognition of caregivers, which is more consistent with emergence delirium than uncontrolled pain."},{"text":"Hypoxemia; treat with supplemental oxygen and airway repositioning","label":"B","correct":false,"rationale":"Incorrect: an SpO2 of 99% on room air with no obstruction excludes hypoxia as the cause of the agitation."},{"text":"Local anesthetic systemic toxicity; treat with intravenous lipid emulsion","label":"C","correct":false,"rationale":"Incorrect: no local anesthetic was administered for a mask sevoflurane myringotomy, so lipid rescue is not indicated."},{"text":"Full bladder causing distress; treat with bladder catheterization","label":"D","correct":false,"rationale":"Incorrect: bladder distention was specifically excluded on exam and is an uncommon cause after a brief myringotomy with minimal fluids."},{"text":"Emergence delirium; treat with a small dose of intravenous dexmedetomidine or propofol","label":"E","correct":true,"rationale":"Correct: the self-limited, non-purposeful agitation with lack of caregiver recognition after a sevoflurane anesthetic in a preschool-aged child is classic emergence delirium, which responds to dexmedetomidine, propofol, or an opioid such as fentanyl."}]'::jsonb, 'E', 'Emergence delirium is a transient state of disorientation, non-purposeful agitation, and inconsolability seen most often in children aged 2 to 6 years, particularly after sevoflurane or desflurane and short procedures with little intrinsic pain. It is a diagnosis of exclusion: hypoxia, pain, hypoglycemia, and bladder distention must be ruled out first. The condition is usually self-limited, but distressing or unsafe agitation is treated with dexmedetomidine, propofol, or fentanyl; intraoperative dexmedetomidine or propofol reduces its incidence.', '[{"url":"https://www.openanesthesia.org/keywords/emergence-delirium/","source":"Emergence Delirium in Children"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-021', 'Principles & Preop', 'Principles & Preop', 'Subspecialty Care', 'Preoperative cardiac risk stratification and functional capacity assessment', 'medium', 'A 68-year-old man is scheduled for an elective open right hemicolectomy for colon cancer. His history includes type 2 diabetes on insulin, hypertension, and a transient ischemic attack 3 years ago. He reports that he is able to walk on a flat surface and do light housework but becomes short of breath and has to stop after climbing one flight of stairs. His resting ECG shows nonspecific ST-T changes unchanged from a tracing 1 year ago, and he has no active cardiac symptoms. Vitals are stable. According to the ACC/AHA stepwise approach to perioperative cardiac evaluation, what is the most appropriate next step in his cardiac workup?', '[{"text":"Proceed to surgery without further cardiac testing","label":"A","correct":true,"rationale":"Correct: his procedure carries elevated risk and his functional capacity is poor/indeterminate, but current guidelines recommend proceeding when further testing would not change perioperative management."},{"text":"Obtain pharmacologic stress testing before surgery","label":"B","correct":false,"rationale":"Incorrect: stress testing is only indicated when it would change management, and there is no plan for revascularization purely to reduce noncardiac surgical risk here."},{"text":"Obtain a resting transthoracic echocardiogram to measure ejection fraction","label":"C","correct":false,"rationale":"Incorrect: routine preoperative echocardiography is not indicated in a patient without signs or symptoms of new or worsening heart failure or valvular disease."},{"text":"Refer for coronary angiography with possible preoperative revascularization","label":"D","correct":false,"rationale":"Incorrect: prophylactic coronary revascularization before noncardiac surgery does not improve outcomes and is reserved for patients who would need it independent of surgery."},{"text":"Cancel surgery and refer to cardiology for a 6-week optimization program","label":"E","correct":false,"rationale":"Incorrect: cancellation is unwarranted for an oncologic resection in a stable patient when no intervention would alter perioperative management."}]'::jsonb, 'A', 'In the ACC/AHA stepwise algorithm, after confirming the absence of an acute coronary syndrome and estimating combined surgical/clinical risk, the decision to test hinges on whether functional capacity is adequate AND whether testing would change management. Even though this patient has poor functional capacity (<4 METs) and an elevated Revised Cardiac Risk Index, additional noninvasive testing is recommended only if the result would alter perioperative care. Because neither revascularization nor cancellation is indicated for this stable patient, the correct step is to proceed to surgery with appropriate medical optimization and monitoring.', '[{"url":"https://www.openanesthesia.org/keywords/preoperative-cardiac-risk-stratification-and-evaluation/","source":"Preoperative Cardiac Risk Stratification and Evaluation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-022', 'Principles & Preop', 'Principles & Preop', 'Subspecialty Care', 'Preoperative airway assessment and difficult airway prediction', 'medium', 'During a preoperative airway examination of a 52-year-old woman scheduled for thyroidectomy, you ask her to sit upright, open her mouth maximally, and protrude her tongue without phonating. You can see the soft palate and the base of the uvula, but the uvular tip and the tonsillar pillars are obscured by the tongue. She has a thyromegaly, a thyromental distance of 5 cm, and full neck extension. Which modified Mallampati class best describes this airway view, and what is its general significance?', '[{"text":"Class I — full view of the soft palate, uvula, and tonsillar pillars; reassuring for easy laryngoscopy","label":"A","correct":false,"rationale":"Incorrect: Class I requires visualization of the entire uvula and pillars, which are obscured in this patient."},{"text":"Class III — only the soft palate and the base of the uvula are visible; associated with increased likelihood of difficult laryngoscopy","label":"B","correct":true,"rationale":"Correct: visualization limited to the soft palate and uvular base defines class III, which correlates with a higher rate of difficult intubation."},{"text":"Class II — soft palate and uvula visible but pillars obscured; generally favorable","label":"C","correct":false,"rationale":"Incorrect: Class II still permits visualization of the uvula in its entirety, whereas here only the uvular base is seen."},{"text":"Class IV — only the hard palate is visible; predicts the most difficult view","label":"D","correct":false,"rationale":"Incorrect: class IV is reserved for cases in which the soft palate cannot be seen at all and only the hard palate is visible."},{"text":"Class 0 — the epiglottis is visible; an extremely favorable view","label":"E","correct":false,"rationale":"Incorrect: class 0 requires direct visualization of the epiglottis, which is not described here."}]'::jsonb, 'B', 'The modified Mallampati classification is performed with the patient seated, mouth maximally open, tongue protruded, and without phonation. Class I shows the soft palate, fauces, uvula, and pillars; class II shows the soft palate, fauces, and uvula; class III shows only the soft palate and the base of the uvula; and class IV shows only the hard palate. Higher classes (III and IV) are associated with an increased risk of difficult laryngoscopy, though the test has modest sensitivity and should be combined with other predictors such as thyromental distance and neck mobility.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK585119/","source":"Mallampati Score - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-023', 'Neuro', 'Neuro', 'Subspecialty Care', 'Cerebral autoregulation and CPP management in traumatic brain injury', 'medium', 'A 58-year-old man with longstanding poorly controlled hypertension (home BP often 170/100 mmHg) sustains a severe traumatic brain injury in a motor vehicle collision. An intraventricular catheter reads an intracranial pressure (ICP) of 22 mmHg. On arrival his blood pressure is 150/90 mmHg (MAP 110 mmHg). The neurosurgical team asks you to target a cerebral perfusion pressure (CPP) of 60-70 mmHg per Brain Trauma Foundation guidance while you manage his anesthetic for ICP control. Compared with a previously normotensive patient, which feature of this patient''s cerebral autoregulation most directly increases his risk of cerebral ischemia if his MAP is allowed to fall toward 65 mmHg?', '[{"text":"Chronic hypertension shifts the autoregulatory curve to the left, lowering the threshold at which cerebral blood flow becomes pressure-passive","label":"A","correct":false,"rationale":"Incorrect: chronic hypertension shifts the curve to the right, not left; a leftward shift would make him more tolerant of low MAP, the opposite of the actual risk."},{"text":"Chronic hypertension abolishes autoregulation entirely so cerebral blood flow is linearly pressure-dependent across all MAP values","label":"B","correct":false,"rationale":"Incorrect: autoregulation is preserved but its operating range is shifted, not abolished, in chronic hypertension."},{"text":"Chronic hypertension shifts the autoregulatory curve to the right, raising the lower limit of autoregulation so ischemia occurs at a higher MAP","label":"C","correct":true,"rationale":"Correct: sustained hypertension shifts the entire autoregulation curve rightward, elevating the lower autoregulatory threshold so that a MAP tolerated by a normotensive patient may already be below this patient''s ischemic limit."},{"text":"Chronic hypertension widens the autoregulatory plateau, broadening the MAP range over which cerebral blood flow stays constant","label":"D","correct":false,"rationale":"Incorrect: chronic hypertension does not widen the plateau; if anything the curve shifts rightward and the safe range relative to baseline narrows."},{"text":"Chronic hypertension lowers the upper limit of autoregulation, making hyperemia the dominant risk at a MAP of 65 mmHg","label":"E","correct":false,"rationale":"Incorrect: the upper limit shifts upward (rightward) in chronic hypertension, and a MAP of 65 mmHg poses an ischemic—not hyperemic—threat."}]'::jsonb, 'C', 'Cerebral autoregulation maintains roughly constant cerebral blood flow across a MAP of about 60-160 mmHg (CPP ~50-150 mmHg) in healthy adults. Chronic hypertension shifts this curve to the right, raising both the lower and upper limits, so a chronically hypertensive patient becomes ischemic at a MAP that a normotensive patient would tolerate. This is why guidelines caution against aggressively lowering MAP and recommend keeping pressure within roughly 20-25% of baseline; in TBI, driving CPP to the low end of a generic target may fall below this patient''s shifted lower autoregulatory limit.', '[{"url":"https://www.openanesthesia.org/keywords/cerebral-autoregulation/","source":"Cerebral Autoregulation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-024', 'Neuro', 'Neuro', 'Subspecialty Care', 'Venous air embolism in sitting-position posterior fossa surgery', 'medium', 'A 44-year-old woman undergoes resection of a posterior fossa meningioma in the sitting position under general anesthesia. About 90 minutes into the case, while the surgeon is working near a venous sinus, the end-tidal CO2 abruptly falls from 35 to 19 mmHg, the precordial Doppler emits a sudden harsh ''mill-wheel'' churning sound, and the blood pressure drops to 78/44 mmHg. A right atrial catheter is in place. After asking the surgeon to flood the field with saline and applying jugular venous compression, which intervention is the most appropriate immediate next step?', '[{"text":"Place the patient in steep reverse Trendelenburg to lower venous pressure at the surgical site","label":"A","correct":false,"rationale":"Incorrect: reverse Trendelenburg would worsen the situation by further lowering pressure at the wound, promoting continued air entrainment."},{"text":"Increase the tidal volume and add 10 cmH2O of PEEP to raise mean airway pressure and tamponade the venous opening","label":"B","correct":false,"rationale":"Incorrect: high PEEP is unreliable for stopping entrainment and can promote paradoxical air embolism via a patent foramen ovale by raising right atrial pressure."},{"text":"Administer a 500 mL crystalloid bolus and start a phenylephrine infusion before any other maneuver","label":"C","correct":false,"rationale":"Incorrect: although hemodynamic support is appropriate, it is adjunctive and should not precede stopping nitrous oxide, giving 100% oxygen, and aspirating the catheter."},{"text":"Discontinue nitrous oxide if in use, deliver 100% oxygen, and aspirate air from the right atrial catheter","label":"D","correct":true,"rationale":"Correct: stopping nitrous oxide prevents expansion of entrained air, 100% oxygen supports oxygenation and aids nitrogen washout from the bubble, and aspirating the right atrial catheter directly removes air from the heart."},{"text":"Hyperventilate the patient to an end-tidal CO2 of 25 mmHg to reduce cerebral blood volume and brain bulk","label":"E","correct":false,"rationale":"Incorrect: hyperventilation does not treat venous air embolism and the low end-tidal CO2 here reflects dead-space from the embolism, not a target to chase."}]'::jsonb, 'D', 'Venous air embolism is a major hazard of sitting-position posterior fossa surgery, where the wound lies above the heart and open venous channels entrain air. The classic signs are a sudden drop in end-tidal CO2 (increased dead space), a mill-wheel murmur or Doppler change, and hypotension. Management is to notify the surgeon to occlude the source (flood the field, wax bone edges, jugular compression), discontinue nitrous oxide and give 100% oxygen to prevent bubble expansion and aid resorption, aspirate air through a right atrial catheter, and support hemodynamics. Nitrous oxide is contraindicated once VAE is suspected because it rapidly enlarges the air bubble.', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-025', 'Neuro', 'Neuro', 'Subspecialty Care', 'Anesthetic effects on intraoperative motor evoked potential monitoring', 'medium', 'A 16-year-old girl is undergoing posterior spinal instrumentation and fusion for adolescent idiopathic scoliosis. Intraoperative neuromonitoring includes both somatosensory evoked potentials (SSEPs) and transcranial motor evoked potentials (MEPs). The neurophysiologist tells you that the MEP signals have become difficult to obtain and asks you to optimize the anesthetic so that reliable MEP recordings are possible during the correction maneuver. Which anesthetic management change is most likely to improve the quality of the transcranial MEP recordings?', '[{"text":"Maintain a continuous nondepolarizing neuromuscular blockade titrated to a train-of-four of two twitches","label":"A","correct":false,"rationale":"Incorrect: neuromuscular blockade attenuates the compound muscle action potential that MEPs depend on, degrading rather than improving motor recordings."},{"text":"Increase the inhaled sevoflurane concentration to 1.5 MAC to deepen anesthesia and reduce movement","label":"B","correct":false,"rationale":"Incorrect: halogenated volatile agents depress MEP amplitude in a dose-dependent fashion (affecting MEPs more than SSEPs), so increasing sevoflurane worsens the signal."},{"text":"Add a high-dose bolus of dexmedetomidine to provide background sedation and reduce volatile requirements","label":"C","correct":false,"rationale":"Incorrect: while low-dose dexmedetomidine may be an adjunct, high-dose boluses can depress MEP amplitude and are not the primary fix for poor signals."},{"text":"Deepen the anesthetic with a bolus of nitrous oxide added to the volatile carrier gas","label":"D","correct":false,"rationale":"Incorrect: nitrous oxide depresses evoked potential amplitudes, particularly MEPs, and adding it would further degrade the recordings."},{"text":"Transition to a total intravenous anesthetic with propofol and an opioid infusion while minimizing volatile agent","label":"E","correct":true,"rationale":"Correct: propofol-based TIVA with an opioid suppresses MEPs far less than volatile agents, making it the preferred technique for reliable motor monitoring."}]'::jsonb, 'E', 'Transcranial motor evoked potentials are highly sensitive to anesthetic depression, and halogenated volatile agents and nitrous oxide reduce MEP amplitude in a dose-dependent manner—more so than they affect SSEPs. A propofol-based total intravenous anesthetic with an opioid is therefore the standard technique when reliable MEP monitoring is required, as in scoliosis correction. Because MEPs are recorded as compound muscle action potentials, neuromuscular blockade must be avoided or kept minimal; deep blockade abolishes the motor response even though SSEPs are unaffected.', '[{"url":"https://www.openanesthesia.org/keywords/evoked-potentials-modalities-and-anesthetic-effects/","source":"Evoked Potentials: Modalities and Anesthetic Effects - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-026', 'Obstetric', 'Obstetric', 'Subspecialty Care', 'Hypertensive disorders of pregnancy — magnesium sulfate toxicity', 'medium', 'A 33-year-old G1 woman at 35 weeks with preeclampsia with severe features is receiving an intravenous magnesium sulfate infusion for seizure prophylaxis. Her blood pressure is controlled at 148/94 mmHg. Over the past 30 minutes she has become increasingly drowsy and reports flushing and weakness. On examination her patellar deep tendon reflexes are absent, respiratory rate is 10/min, and oxygen saturation is 93% on room air. Urine output has fallen to 10 mL/hr. What is the most appropriate immediate intervention?', '[{"text":"Stop the magnesium infusion and administer intravenous calcium gluconate","label":"A","correct":true,"rationale":"Stopping the magnesium and giving IV calcium (the direct physiologic antagonist) is the correct management of acute magnesium toxicity with respiratory depression and areflexia."},{"text":"Increase the magnesium sulfate infusion rate to better control her neurologic symptoms","label":"B","correct":false,"rationale":"Her drowsiness, areflexia, and respiratory depression are signs of magnesium toxicity, so increasing the dose would deepen the toxicity and risk respiratory and cardiac arrest."},{"text":"Administer a benzodiazepine for presumed impending eclamptic seizure","label":"C","correct":false,"rationale":"Her depressed sensorium reflects magnesium toxicity rather than seizure activity, and a benzodiazepine would further depress respiration."},{"text":"Administer furosemide to increase urine output and accelerate magnesium clearance","label":"D","correct":false,"rationale":"Diuresis is too slow to reverse acute respiratory depression and risks worsening hypovolemia, so it does not address the immediate threat."},{"text":"Administer naloxone to reverse the respiratory depression","label":"E","correct":false,"rationale":"Naloxone reverses opioid-induced respiratory depression but has no effect on magnesium-induced neuromuscular and respiratory depression."}]'::jsonb, 'A', 'Loss of deep tendon reflexes is the earliest reliable clinical sign of magnesium toxicity (typically around 8-10 mg/dL), followed by respiratory depression (~12 mg/dL) and ultimately cardiac arrest at higher levels. Oliguria from preeclampsia reduces renal magnesium clearance and predisposes to accumulation. Immediate management is to stop the infusion and give IV calcium gluconate (1 g) or calcium chloride, which directly antagonizes magnesium at the neuromuscular junction, while supporting ventilation. Reflexes should be monitored at the bedside during any magnesium infusion.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430839/","source":"Hypertension In Pregnancy — StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-027', 'Obstetric', 'Obstetric', 'Subspecialty Care', 'Obstetric hemorrhage — uterotonic selection in uterine atony', 'medium', 'A 38-year-old G4P3 woman with chronic hypertension delivers a 4,300 g infant after a prolonged second stage. Her current blood pressure is 168/102 mmHg. Within minutes of delivery she has brisk vaginal bleeding; the uterus is boggy and palpable above the umbilicus. Oxytocin is already infusing at a high rate and fundal massage has been started, but bleeding continues and the uterus remains atonic. Which second-line uterotonic is most appropriate to administer next?', '[{"text":"Methylergonovine 200 mcg intramuscularly","label":"A","correct":false,"rationale":"Methylergonovine is contraindicated in this hypertensive patient because its alpha-adrenergic vasoconstriction can precipitate a severe, sometimes fatal, hypertensive crisis or stroke."},{"text":"Carboprost (15-methyl PGF2-alpha) 250 mcg intramuscularly","label":"B","correct":true,"rationale":"Carboprost effectively treats atony and is the preferred second-line agent here because the contraindicated alternative is the ergot, though it should be used cautiously given any reactive airway disease."},{"text":"A repeat intravenous bolus of oxytocin 40 units given as rapid push","label":"C","correct":false,"rationale":"Rapid undiluted oxytocin boluses cause vasodilation, hypotension, and tachycardia, and simply escalating an agent that has already failed does not add a new mechanism."},{"text":"Intravenous magnesium sulfate to relax the uterus and reduce blood pressure","label":"D","correct":false,"rationale":"Magnesium is a tocolytic that relaxes uterine smooth muscle and would worsen atony and bleeding, the opposite of what is needed."},{"text":"Terbutaline 250 mcg subcutaneously","label":"E","correct":false,"rationale":"Terbutaline is a beta-agonist tocolytic that further relaxes the uterus, aggravating atony and hemorrhage."}]'::jsonb, 'B', 'This is uterine atony, the leading cause of primary postpartum hemorrhage, with classic risk factors of grand multiparity, macrosomia, and prolonged labor. When oxytocin and massage fail, a second-line uterotonic with a different mechanism is indicated. Methylergonovine (an ergot alkaloid) is contraindicated in hypertension and preeclampsia because of its vasoconstrictive effect, so carboprost is the appropriate choice here — with the caveat that prostaglandin F2-alpha analogues can cause bronchospasm and should be avoided in significant asthma. Misoprostol is another option when both ergots and prostaglandin injectables are contraindicated.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499988/","source":"Postpartum Hemorrhage — StatPearls (NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-028', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Patient selection and facility appropriateness (obstructive sleep apnea)', 'medium', 'A 54-year-old man with a BMI of 41 kg/m2, hypertension, and type 2 diabetes is scheduled for an elective unilateral inguinal hernia repair at a freestanding ambulatory surgery center. He reports loud snoring, witnessed apneas, and daytime somnolence; his STOP-Bang score is 6. He has never had a formal sleep study and is not on CPAP. His blood pressure is 148/88 mmHg and SpO2 is 96% on room air. The surgeon plans general anesthesia with an LMA and expects to use intraoperative and postoperative opioids for analgesia. Which factor most strongly supports rescheduling this case at a facility with extended postoperative monitoring rather than proceeding at the freestanding center?', '[{"text":"His BMI of 41 kg/m2 alone, which is an absolute contraindication to ambulatory surgery","label":"A","correct":false,"rationale":"Incorrect, because obesity by itself is not an absolute contraindication to ambulatory surgery; appropriately selected patients with high BMI can undergo outpatient procedures when comorbidities are optimized."},{"text":"His blood pressure of 148/88 mmHg, which mandates inpatient management","label":"B","correct":false,"rationale":"Incorrect, because stage 1 hypertension without evidence of end-organ ischemia does not require inpatient management and is not a reason to cancel or transfer an ambulatory case."},{"text":"The combination of a high STOP-Bang score (presumed severe OSA) with an anesthetic plan requiring substantial postoperative opioids","label":"C","correct":true,"rationale":"Correct, because presumed-severe untreated OSA combined with an opioid-dependent analgesic plan markedly raises the risk of postoperative respiratory depression and airway obstruction, which exceeds what a freestanding center can safely monitor."},{"text":"The planned use of an LMA, which is unsafe in patients with obstructive sleep apnea","label":"D","correct":false,"rationale":"Incorrect, because a supraglottic airway is not contraindicated in OSA and the airway device choice is not the principal driver of postoperative disposition risk."},{"text":"His type 2 diabetes, which precludes same-day discharge after general anesthesia","label":"E","correct":false,"rationale":"Incorrect, because well-controlled diabetes is routinely managed in the ambulatory setting and does not by itself preclude same-day discharge."}]'::jsonb, 'C', 'Patient selection for the freestanding ambulatory setting hinges on matching procedural and anesthetic risk to the facility''s monitoring capability. A patient with presumed severe, untreated OSA (STOP-Bang 6) who will require significant postoperative opioids faces a meaningfully elevated risk of opioid-induced respiratory depression and airway obstruction; the SAMBA/ASA guidance favors an opioid-sparing, multimodal plan and a facility capable of extended monitoring when severe OSA cannot be mitigated. Isolated factors such as obesity, controlled hypertension, or diabetes are not independent disqualifiers.', '[{"url":"https://www.openanesthesia.org/keywords/obstructive-sleep-apnea/","source":"Obstructive Sleep Apnea: Pathophysiology (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-029', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Postoperative nausea and vomiting prophylaxis and risk stratification', 'medium', 'A healthy 24-year-old nonsmoking woman is scheduled for an outpatient laparoscopic cholecystectomy under general anesthesia. She reports severe nausea and vomiting after a prior tonsillectomy and a history of motion sickness. The planned anesthetic includes volatile agent maintenance and intraoperative opioids. Recognizing she has four Apfel risk factors, the anesthesia team wants to minimize her postoperative nausea and vomiting (PONV) risk to avoid an unplanned admission. Which intervention is the most effective single modification to reduce her baseline PONV risk?', '[{"text":"Administering a single prophylactic dose of ondansetron at the end of surgery as the only intervention","label":"A","correct":false,"rationale":"Incorrect, because a single antiemetic provides only modest relative risk reduction and is inadequate as sole prophylaxis in a patient with four risk factors."},{"text":"Adding nitrous oxide to reduce the required volatile concentration","label":"B","correct":false,"rationale":"Incorrect, because nitrous oxide is itself an independent emetogenic agent and would increase rather than decrease PONV risk."},{"text":"Withholding all antiemetic prophylaxis and treating nausea only if it occurs in recovery","label":"C","correct":false,"rationale":"Incorrect, because a rescue-only strategy is inappropriate for a high-risk patient and ignores the value of reducing baseline risk and combining prophylactic agents."},{"text":"Replacing volatile-based maintenance with propofol total intravenous anesthesia (TIVA) and minimizing opioids","label":"D","correct":true,"rationale":"Correct, because substituting a propofol-based TIVA for volatile maintenance and reducing opioids directly removes two major anesthetic triggers, lowering the patient''s baseline risk before pharmacologic prophylaxis is added."},{"text":"Giving generous intraoperative opioids to ensure deep analgesia and prevent pain-related nausea","label":"E","correct":false,"rationale":"Incorrect, because opioids are a dose-dependent cause of PONV, so liberal opioid use raises rather than lowers her risk."}]'::jsonb, 'D', 'In a patient with four Apfel risk factors, the most impactful step is to lower baseline risk by modifying the anesthetic itself rather than relying on a single antiemetic. Switching from volatile maintenance to propofol TIVA and minimizing opioids each independently reduce PONV, and these baseline reductions are then layered with multimodal pharmacologic prophylaxis using agents from different receptor classes. Nitrous oxide and liberal opioids both worsen PONV and should be avoided in this setting.', '[{"url":"https://www.openanesthesia.org/keywords/postoperative-nausea-and-vomiting/","source":"Postoperative Nausea and Vomiting in Adults (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-030', 'Ambulatory', 'Ambulatory', 'Subspecialty Care', 'Perioperative emergencies in the ambulatory setting (malignant hyperthermia)', 'hard', 'During an elective outpatient knee arthroscopy under general anesthesia with sevoflurane and a single dose of succinylcholine for intubation at a freestanding surgery center, a 19-year-old man develops an unexplained rise in end-tidal CO2 to 68 mmHg despite increased minute ventilation, masseter rigidity, tachycardia to 140 bpm, and a temperature rising from 36.8 to 39.1 C over 20 minutes. Malignant hyperthermia is suspected. After calling for help and discontinuing the triggering agents, what is the single most important next pharmacologic intervention?', '[{"text":"Administer a beta-blocker to control the tachycardia","label":"A","correct":false,"rationale":"Incorrect, because the tachycardia reflects the underlying hypermetabolic crisis, and beta-blockade neither treats the cause nor addresses the life-threatening hyperthermia and acidosis."},{"text":"Give intravenous sodium bicarbonate as the primary treatment for the crisis","label":"B","correct":false,"rationale":"Incorrect, because while bicarbonate may be used to help correct metabolic acidosis, it is an adjunct and does not reverse the underlying ryanodine-receptor calcium dysregulation."},{"text":"Administer a calcium channel blocker such as verapamil to lower intracellular calcium","label":"C","correct":false,"rationale":"Incorrect, because calcium channel blockers do not treat MH and can cause dangerous hyperkalemia and cardiovascular collapse when combined with dantrolene."},{"text":"Deepen anesthesia with additional sevoflurane to control the sympathetic response","label":"D","correct":false,"rationale":"Incorrect, because sevoflurane is itself an MH trigger and continuing it would worsen the crisis rather than control it."},{"text":"Administer intravenous dantrolene 2.5 mg/kg immediately and repeat as needed","label":"E","correct":true,"rationale":"Correct, because dantrolene is the only definitive treatment for an MH crisis and must be given without delay at an initial dose of 2.5 mg/kg, titrated until the hypermetabolic signs resolve."}]'::jsonb, 'E', 'Malignant hyperthermia is a pharmacogenetic hypermetabolic crisis triggered by volatile agents and succinylcholine; the earliest and most sensitive sign is an unexplained rise in end-tidal CO2, often with masseter rigidity after succinylcholine. After stopping triggers, calling for help, and hyperventilating with 100% oxygen, dantrolene 2.5 mg/kg IV is the definitive treatment and must be given immediately and repeated until the hypermetabolic state resolves. Because MH can occur in any setting that uses triggering agents, every ambulatory facility administering volatile anesthetics or succinylcholine must stock a full supply of dantrolene and a transfer plan.', '[{"url":"https://www.openanesthesia.org/keywords/malignant-hyperthermia/","source":"Malignant Hyperthermia (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-031', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'Urology: TURP syndrome (dilutional hyponatremia from irrigation fluid absorption)', 'medium', 'A 72-year-old man with benign prostatic hyperplasia undergoes monopolar transurethral resection of the prostate (TURP) under spinal anesthesia with 1.5% glycine irrigation. About 50 minutes into the resection, he becomes restless and reports nausea and blurred vision, then complains of a headache. His blood pressure rises to 168/96 mmHg, heart rate falls to 52/min, and SpO2 is 97% on supplemental oxygen. A stat serum sodium returns at 118 mEq/L. Which of the following is the most appropriate next step in management?', '[{"text":"Ask the surgeon to stop the resection and irrigation, then begin 3% hypertonic saline at approximately 1 mL/kg/hr","label":"A","correct":true,"rationale":"Correct: this patient has symptomatic, severe TURP-syndrome hyponatremia, so the irrigant absorption source must be halted and slow correction with hypertonic saline initiated while limiting the rise to about 10 mEq/L per 24 hours."},{"text":"Rapidly infuse 1 liter of 0.9% normal saline to restore the sodium toward normal","label":"B","correct":false,"rationale":"Incorrect: isotonic saline corrects sodium far too slowly for symptomatic severe hyponatremia and adds volume to an already fluid-overloaded patient."},{"text":"Administer atropine and continue the resection while monitoring the sodium","label":"C","correct":false,"rationale":"Incorrect: treating only the bradycardia while continuing irrigation allows further hypotonic fluid absorption and progression toward seizures, coma, and death."},{"text":"Give 0.5 mEq/kg of sodium bicarbonate to correct the presumed acidosis","label":"D","correct":false,"rationale":"Incorrect: the problem is dilutional hyponatremia and cerebral edema, not acidosis, and bicarbonate does not address the sodium deficit or the ongoing absorption."},{"text":"Restrict all intravenous and irrigation fluids and observe without sodium therapy","label":"E","correct":false,"rationale":"Incorrect: passive fluid restriction is inadequate for a symptomatic patient at 118 mEq/L who needs active, controlled sodium correction to prevent cerebral herniation."}]'::jsonb, 'A', 'TURP syndrome results from intravascular absorption of hypotonic irrigation fluid through open prostatic venous sinuses, producing dilutional hyponatremia, volume overload, and cerebral edema; glycine solutions add hyperammonemia and transient visual disturbances. The first step is always to stop the irrigation/resection source, secure oxygenation, and obtain a stat sodium. Symptomatic severe hyponatremia (e.g., 118 mEq/L with neurologic signs) warrants 3% saline at about 1 mL/kg/hr with the correction capped near 10 mEq/L per 24 hours to avoid osmotic demyelination.', '[{"url":"https://www.openanesthesia.org/keywords/hyponatermia-and-transurethral-resection-of-prostate-syndrome/","source":"Hyponatremia and Transurethral Resection of Prostate Syndrome - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-032', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'Orthopedics: pneumatic tourniquet deflation physiology', 'medium', 'A 24-year-old healthy man undergoes open reduction and internal fixation of a tibial plateau fracture under general anesthesia with a thigh pneumatic tourniquet inflated for 95 minutes. He is volume-replete and normothermic, ventilated to an end-tidal CO2 of 35 mmHg. Immediately after the surgeon deflates the tourniquet, the anesthetist notes the end-tidal CO2 climbs to 48 mmHg over about one minute and the mean arterial pressure falls from 78 to 60 mmHg. Which of the following best explains these findings?', '[{"text":"Acute pulmonary embolism from dislodged deep venous thrombus","label":"A","correct":false,"rationale":"Incorrect: a large PE would classically cause a fall (not a rise) in end-tidal CO2 from increased dead-space ventilation, along with hypoxemia and right-heart strain."},{"text":"Washout of CO2-rich, vasoactive metabolites from the previously ischemic limb into the central circulation","label":"B","correct":true,"rationale":"Correct: reperfusion of the ischemic limb returns accumulated CO2, lactate, and potassium centrally, transiently raising end-tidal CO2 and lowering systemic vascular resistance and arterial pressure."},{"text":"Malignant hyperthermia triggered by the volatile anesthetic","label":"C","correct":false,"rationale":"Incorrect: MH produces a sustained, progressive rise in end-tidal CO2 with hyperthermia, rigidity, and tachycardia rather than a brief spike timed precisely to cuff release."},{"text":"Inadequate minute ventilation from a kinked or disconnected circuit","label":"D","correct":false,"rationale":"Incorrect: a circuit problem is unrelated to tourniquet deflation timing and would not resolve spontaneously as reperfusion metabolites are cleared over several minutes."},{"text":"Light anesthesia causing sympathetic activation and hypercarbia","label":"E","correct":false,"rationale":"Incorrect: light anesthesia typically raises blood pressure and heart rate, whereas this patient shows hypotension coincident with cuff deflation, which is the opposite hemodynamic picture."}]'::jsonb, 'B', 'Release of a lower-extremity pneumatic tourniquet allows CO2-rich, acidotic, hyperkalemic venous blood from the ischemic limb to re-enter the systemic circulation, producing a transient spike in end-tidal CO2 (peaking around one minute and normalizing within about ten minutes) and a fall in central venous pressure and arterial pressure that can persist roughly fifteen minutes. The metabolic washout also causes a brief metabolic acidosis. Anticipatory management includes transiently increasing minute ventilation and ensuring euvolemia before deflation. The hemodynamic dip is usually self-limited but can be marked in hypovolemic patients.', '[{"url":"https://www.openanesthesia.org/keywords/lower-extremity-tourniquet-deflation-physiologic-effects/","source":"Lower extremity tourniquet deflation: Physiologic effects - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-033', 'Orthopedic, Urology & GYN', 'Orthopedic, Urology & GYN', 'Subspecialty Care', 'GYN/laparoscopy: vagal bradyarrhythmia from CO2 pneumoperitoneum insufflation', 'medium', 'A 38-year-old woman with no significant comorbidities undergoes laparoscopic hysterectomy under general anesthesia. Shortly after the surgeon insufflates the abdomen with CO2 to establish pneumoperitoneum, the patient develops sinus bradycardia to 38/min with a brief run of junctional rhythm; blood pressure falls to 84/50 mmHg. SpO2 remains 99% and end-tidal CO2 is stable at 36 mmHg. Which of the following is the most likely cause of this acute event?', '[{"text":"Carbon dioxide venous gas embolism","label":"A","correct":false,"rationale":"Incorrect: a significant CO2 embolism typically causes a sudden fall in end-tidal CO2 with hypoxemia and cardiovascular collapse, whereas this patient''s end-tidal CO2 and saturation are unchanged."},{"text":"Hypercarbia-induced catecholamine surge","label":"B","correct":false,"rationale":"Incorrect: systemic CO2 absorption raises sympathetic tone causing tachycardia and hypertension, the opposite of the bradycardia and hypotension observed."},{"text":"A vagally mediated reflex from acute peritoneal stretch during insufflation","label":"C","correct":true,"rationale":"Correct: rapid distension of the peritoneum at the onset of insufflation can trigger a vagal reflex producing bradyarrhythmias and hypotension, which is the classic timing and presentation here."},{"text":"Tension capnothorax from CO2 tracking into the pleural space","label":"D","correct":false,"rationale":"Incorrect: a capnothorax produces rising airway pressures, hypoxemia, and hemodynamic compromise over time rather than an immediate vagal bradycardia at the moment of insufflation."},{"text":"Endobronchial migration of the endotracheal tube from cephalad diaphragm shift","label":"E","correct":false,"rationale":"Incorrect: mainstem intubation causes hypoxemia and high peak airway pressures, not an abrupt isolated bradyarrhythmia, and the saturation here is normal."}]'::jsonb, 'C', 'At the onset of CO2 pneumoperitoneum, sudden peritoneal stretch can provoke a vagal reflex producing bradycardia, junctional rhythms, or even asystole, particularly with rapid insufflation. Appropriate management is to ask the surgeon to desufflate, treat with an anticholinergic such as atropine, and re-insufflate slowly at a lower pressure. This is distinct from the later sympathetic effects of absorbed CO2 (hypertension, tachycardia) and from CO2 venous embolism, which lowers end-tidal CO2 and oxygen saturation.', '[{"url":"https://www.openanesthesia.org/keywords/anesthesia-for-laparoscopic-and-robotic-surgery/","source":"Anesthesia for Laparoscopic and Robotic Surgery - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-034', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Local anesthetic systemic toxicity (LAST) management', 'medium', 'A 68-kg woman undergoes an ultrasound-guided interscalene brachial plexus block with 30 mL of 0.5% ropivacaine for shoulder arthroscopy. About 90 seconds after injection she reports a metallic taste and circumoral numbness, then becomes agitated and has a generalized tonic-clonic seizure, followed by a wide-complex bradycardia with a blood pressure of 70/40 mmHg. The seizure is terminated with midazolam and ventilation is supported with 100% oxygen. In addition to starting chest compressions if a pulse is lost, which intervention is most appropriate as part of her resuscitation?', '[{"text":"Administer a standard ACLS epinephrine dose of 1 mg IV every 3 to 5 minutes","label":"A","correct":false,"rationale":"During local anesthetic systemic toxicity, full ACLS-dose epinephrine can impair lipid resuscitation and worsen arrhythmias, so the dose should be reduced rather than given at the standard 1 mg."},{"text":"Give a calcium channel blocker to control the wide-complex rhythm","label":"B","correct":false,"rationale":"Calcium channel blockers and beta-blockers are specifically discouraged in LAST because they further depress an already compromised myocardium."},{"text":"Administer a propofol infusion to both treat the seizure and provide a lipid load","label":"C","correct":false,"rationale":"Propofol is not a substitute for lipid emulsion; its lipid content is far too low to be therapeutic and its cardiodepressant effect is dangerous in a hypotensive patient."},{"text":"Administer a 1.5 mL/kg bolus of 20% intravenous lipid emulsion followed by an infusion","label":"D","correct":true,"rationale":"Intravenous lipid emulsion is the established standard treatment for LAST, given as an approximately 1.5 mL/kg bolus of the 20% formulation followed by a continuous infusion, and it should be started early once toxicity is recognized."},{"text":"Give vasopressin 40 units IV in place of epinephrine","label":"E","correct":false,"rationale":"Vasopressin is not recommended in LAST resuscitation and has been associated with worse outcomes in this setting, so it should be avoided rather than substituted for epinephrine."}]'::jsonb, 'D', 'This is classic local anesthetic systemic toxicity (LAST): prodromal CNS symptoms (metallic taste, circumoral numbness), a seizure, and cardiovascular collapse shortly after a large-volume plexus injection. The cornerstone of treatment, alongside airway control, seizure suppression with benzodiazepines, and modified ACLS, is intravenous 20% lipid emulsion given as a ~1.5 mL/kg bolus followed by an infusion. During LAST, epinephrine doses should be reduced (to roughly 1 mcg/kg or less), and vasopressin, calcium channel blockers, beta-blockers, and additional local anesthetics should be avoided.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK499964/","source":"Local Anesthetic Toxicity - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-035', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Truncal/peripheral nerve block coverage (TAP block)', 'medium', 'A 58-year-old man undergoes an open right hemicolectomy. As part of a multimodal opioid-sparing plan, the surgical team performs bilateral ultrasound-guided transversus abdominis plane (TAP) blocks with local anesthetic. In the recovery unit he reports good relief of pain at his midline and flank incision sites but continues to have deep, cramping pain that he localizes vaguely to the center of his abdomen, with associated nausea. Which statement best explains why the TAP block has not relieved this component of his pain?', '[{"text":"The TAP block was placed too superficially and deposited local anesthetic in the subcutaneous tissue","label":"A","correct":false,"rationale":"A technical failure would also reduce relief of his incisional (somatic) pain, but his wound pain is well controlled, so a misplaced injection does not explain the isolated deep abdominal pain."},{"text":"The TAP block only provides analgesia when combined with intrathecal morphine","label":"B","correct":false,"rationale":"A TAP block produces analgesia on its own from local anesthetic spread to abdominal wall nerves and does not require intrathecal morphine to be effective."},{"text":"Cramping abdominal pain after bowel surgery is always neuropathic and unresponsive to any regional technique","label":"C","correct":false,"rationale":"Postoperative deep abdominal cramping is predominantly visceral nociceptive pain, not neuropathic, and it can respond to techniques that cover visceral afferents such as a thoracic epidural."},{"text":"Local anesthetic from a TAP block is too rapidly absorbed to provide any meaningful duration of analgesia","label":"D","correct":false,"rationale":"A TAP block provides hours of somatic analgesia, as evidenced by this patient''s well-controlled incisional pain, so inadequate duration does not explain the persistent visceral pain."},{"text":"The TAP block anesthetizes the thoracolumbar somatic nerves of the abdominal wall but does not block visceral afferents","label":"E","correct":true,"rationale":"The TAP block deposits local anesthetic around the T6–L1 somatic nerves supplying the anterior and lateral abdominal wall and parietal peritoneum, so it relieves incisional somatic pain but does not cover visceral afferent pain from the bowel."}]'::jsonb, 'E', 'The TAP block targets the somatic thoracolumbar nerves (approximately T6–L1) coursing in the plane between the internal oblique and transversus abdominis muscles, providing analgesia to the anterior and lateral abdominal wall and parietal peritoneum. A key, frequently tested limitation is that it provides somatic but not visceral analgesia. After bowel surgery, deep cramping mid-abdominal pain arises from visceral afferents and will not be covered by a TAP block; a technique that blocks visceral afferents, such as a thoracic epidural, is needed for that component.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK547730/","source":"Transversus Abdominis Plane Block - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-036', 'Regional & Pain', 'Regional & Pain', 'Subspecialty Care', 'Post-dural puncture headache (neuraxial complication)', 'easy', 'A 24-year-old healthy woman receives a labor epidural. During placement using a loss-of-resistance technique with a 17-gauge Tuohy needle, there is an unintended dural puncture with free flow of cerebrospinal fluid. The epidural is resited at an adjacent interspace and labor proceeds uneventfully. On the second postpartum day she develops a bilateral fronto-occipital headache that is markedly worse when she sits or stands and is relieved within minutes of lying flat; she also reports mild neck stiffness and tinnitus. Her neurologic exam is otherwise normal and she is afebrile. Which feature of this case is most strongly associated with the highest risk of developing this complication?', '[{"text":"Accidental dural puncture with a large-gauge cutting epidural (Tuohy) needle","label":"A","correct":true,"rationale":"Larger-gauge needles and cutting (non-pencil-point) tips cause a bigger dural defect and greater cerebrospinal fluid leak, and an accidental wet tap with a 17-gauge Tuohy needle carries a high incidence of post-dural puncture headache."},{"text":"Her use of a labor epidural rather than a combined spinal-epidural technique","label":"B","correct":false,"rationale":"The analgesic technique label itself does not determine risk; what matters is whether the dura is breached and the size and type of the needle that breaches it."},{"text":"Her supine positioning during epidural placement","label":"C","correct":false,"rationale":"Patient positioning during placement is not an established major determinant of post-dural puncture headache risk."},{"text":"Her relatively low body mass index","label":"D","correct":false,"rationale":"While obesity has a complex relationship with this complication, low BMI is not the dominant risk factor here compared with the large-bore dural breach."},{"text":"The fact that she is afebrile, which favors a low-pressure headache","label":"E","correct":false,"rationale":"Absence of fever helps exclude infectious causes but is not itself a risk factor that increases the likelihood of developing the headache."}]'::jsonb, 'A', 'This is a classic post-dural puncture headache (PDPH): a postural (worse upright, relieved supine) bilateral headache appearing within 5 days of a dural breach, often with neck pain, tinnitus, or other associated symptoms. The single most important risk factor is the dural puncture itself and, in particular, the needle: larger-gauge and cutting (Quincke/Tuohy) needles create a larger dural defect and greater cerebrospinal fluid leak than smaller pencil-point needles, so an accidental wet tap with a 17-gauge Tuohy needle confers a high PDPH incidence. Treatment ranges from conservative measures to a definitive epidural blood patch for severe or persistent cases.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430925/","source":"Postdural Puncture Headache - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-037', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Protamine reaction / cardiopulmonary bypass separation', 'hard', 'A 68-year-old man with type 1 diabetes managed on NPH insulin is undergoing on-pump coronary artery bypass grafting. After successful separation from cardiopulmonary bypass, the surgeon requests heparin reversal and the perfusionist begins administering protamine 1 mg per 100 units of total heparin given. Approximately two minutes into the infusion, the systemic arterial pressure falls from 118/64 mmHg to 62/38 mmHg, the pulmonary artery pressure rises from 28/14 mmHg to 52/30 mmHg, central venous pressure climbs to 22 mmHg, and the right ventricle is seen to be acutely distended and hypokinetic on transesophageal echocardiography. Which of the following is the most appropriate immediate intervention?', '[{"text":"Continue the protamine infusion at a faster rate to fully neutralize circulating heparin","label":"A","correct":false,"rationale":"Incorrect: faster protamine delivery worsens the reaction, and protamine itself, not residual heparin, is driving the hemodynamic collapse."},{"text":"Stop the protamine infusion and treat with an inhaled or intravenous pulmonary vasodilator and inotropic/vasopressor support","label":"B","correct":true,"rationale":"Correct: this presentation is a catastrophic (Type III) protamine reaction with pulmonary vasoconstriction and acute right heart failure, so halting protamine and supporting the right ventricle while lowering pulmonary pressures is the immediate priority."},{"text":"Administer additional intravenous heparin and re-establish cardiopulmonary bypass before any other treatment","label":"C","correct":false,"rationale":"Incorrect: although re-heparinization and returning to bypass may become necessary for refractory collapse, the first step is to stop the offending agent and attempt pharmacologic rescue of the right ventricle."},{"text":"Give a rapid 1 L crystalloid bolus to correct presumed hypovolemia","label":"D","correct":false,"rationale":"Incorrect: the right ventricle is already distended with a high central venous pressure, so aggressive volume loading would further overdistend the failing RV and worsen output."},{"text":"Administer intravenous calcium chloride to reverse protamine-induced myocardial depression","label":"E","correct":false,"rationale":"Incorrect: calcium does not address the pulmonary vasoconstriction and complement/thromboxane-mediated mechanism of a severe protamine reaction and will not relieve the RV afterload."}]'::jsonb, 'B', 'Severe (Type III) protamine reactions produce catastrophic pulmonary vasoconstriction with acute right ventricular pressure overload, systemic hypotension, and elevated pulmonary artery pressures, classically within minutes of administration. Patients on NPH insulin (which contains protamine) and those with fish allergy or prior protamine exposure are at higher risk. Immediate management is to stop the protamine, support the right ventricle with inotropes and vasopressors, and reduce RV afterload with a pulmonary vasodilator; re-heparinization and return to bypass are reserved for refractory cases.', '[{"url":"https://www.openanesthesia.org/keywords/protamine-reaction/","source":"Protamine Reactions (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-038', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Valvular disease: aortic stenosis hemodynamic management', 'medium', 'A 79-year-old woman with severe calcific aortic stenosis (valve area 0.7 cm2, mean gradient 52 mmHg) presents for hip fracture fixation under general anesthesia. Her baseline pressure is 138/82 mmHg and heart rate is 72 bpm in sinus rhythm. Shortly after induction with propofol, her heart rate increases to 124 bpm and is now an irregularly irregular rhythm on the monitor, with the blood pressure falling to 78/50 mmHg. Which of the following best explains why this rhythm is so poorly tolerated in this patient?', '[{"text":"The tachycardia raises myocardial oxygen demand while shortening diastolic coronary perfusion time to the hypertrophied left ventricle","label":"A","correct":false,"rationale":"Incorrect alone: increased demand with reduced diastolic perfusion does contribute to ischemia, but it is not the single best explanation for the abrupt hemodynamic deterioration tied specifically to this rhythm change."},{"text":"Propofol has directly increased systemic vascular resistance, raising afterload across the stenotic valve","label":"B","correct":false,"rationale":"Incorrect: propofol lowers, not raises, systemic vascular resistance, and a fixed valvular obstruction—not changing afterload—is the dominant problem."},{"text":"Loss of the organized atrial contribution to filling of a stiff, hypertrophied left ventricle markedly reduces stroke volume across the fixed obstruction","label":"C","correct":true,"rationale":"Correct: the noncompliant, hypertrophied ventricle in aortic stenosis is heavily dependent on the atrial kick, so the loss of organized atrial contraction in new atrial fibrillation sharply lowers preload, stroke volume, and cardiac output."},{"text":"The increased rate has improved diastolic filling and caused pulmonary edema from volume overload","label":"D","correct":false,"rationale":"Incorrect: tachycardia shortens diastolic filling time rather than improving it, and the acute picture is low output, not volume overload."},{"text":"Aortic stenosis converts the lesion into a volume-overload state in which any tachyarrhythmia causes acute mitral regurgitation","label":"E","correct":false,"rationale":"Incorrect: aortic stenosis is a pressure-overload, not a primary volume-overload lesion, and acute mitral regurgitation is not the mechanism of decompensation here."}]'::jsonb, 'C', 'The hypertrophied, poorly compliant left ventricle of severe aortic stenosis depends heavily on the atrial kick for adequate end-diastolic filling, and on slower heart rates that preserve diastolic filling and coronary perfusion time. New-onset atrial fibrillation removes the organized atrial contribution while the rapid ventricular response shortens diastole, collapsing stroke volume across the fixed obstruction. Management favors maintaining sinus rhythm, avoiding tachycardia and hypotension, and prompt synchronized cardioversion when an acute arrhythmia causes hemodynamic instability.', '[{"url":"https://www.openanesthesia.org/keywords/aortic-stenosis/","source":"Aortic Stenosis: Etiology, Pathophysiology, and Clinical Presentation (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-039', 'Cardiac', 'Cardiac', 'Subspecialty Care', 'Pericardial disease: cardiac tamponade and induction', 'medium', 'A 54-year-old man presents to the operating room for emergency surgical drainage of a large pericardial effusion after a recent type A aortic dissection repair. He is anxious, sitting upright, tachycardic at 128 bpm, with blood pressure 88/70 mmHg, jugular venous distension, and pulsus paradoxus of 18 mmHg; echocardiography shows diastolic right atrial and right ventricular collapse. Which of the following is the most appropriate anesthetic management strategy for induction?', '[{"text":"Perform a standard rapid-sequence induction with propofol and full positive-pressure ventilation immediately after preoxygenation","label":"A","correct":false,"rationale":"Incorrect: propofol-induced vasodilation and myocardial depression plus positive-pressure ventilation can abolish the compensatory tachycardia and preload, precipitating cardiovascular collapse in tamponade."},{"text":"Induce deep general anesthesia and deliberately lower the heart rate with a beta-blocker to improve diastolic filling","label":"B","correct":false,"rationale":"Incorrect: the tachycardia is a compensatory mechanism to maintain cardiac output with a fixed low stroke volume, and slowing the heart rate would reduce output and can be fatal."},{"text":"Give a large dose of an intravenous vasodilator before induction to reduce afterload and augment forward flow","label":"C","correct":false,"rationale":"Incorrect: patients with tamponade are preload-dependent and rely on systemic vascular resistance, so vasodilation can precipitate profound hypotension."},{"text":"Prepare and surgically drain the pericardium under local anesthesia before induction whenever feasible, maintaining spontaneous ventilation and using a hemodynamically stable induction technique","label":"D","correct":true,"rationale":"Correct: relieving the tamponade physiology before or at the moment of induction, while preserving preload, heart rate, contractility, and spontaneous ventilation, is the safest approach to avoid hemodynamic collapse."},{"text":"Aggressively diurese the patient before induction to reduce the pericardial fluid burden","label":"E","correct":false,"rationale":"Incorrect: diuresis reduces the preload that a preload-dependent tamponade patient depends on and does nothing to remove pericardial fluid, risking collapse."}]'::jsonb, 'D', 'Cardiac tamponade impairs diastolic filling, leaving patients dependent on maintained preload, an elevated heart rate, contractility, and systemic vascular resistance, with spontaneous negative-pressure ventilation favoring venous return. The safest strategy is to relieve the effusion before committing to general anesthesia and positive-pressure ventilation—ideally prepping and draining under local anesthesia with the surgeon ready—while using an induction that preserves these compensatory mechanisms. Propofol boluses, deliberate bradycardia, vasodilators, diuresis, and early positive-pressure ventilation can each abolish compensation and cause arrest.', '[{"url":"https://www.openanesthesia.org/keywords/cardiac-tamponade/","source":"Cardiac Tamponade (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-040', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Pulse oximetry physiology and limitations (dyshemoglobins)', 'medium', 'A 58-year-old woman with a 40-pack-year smoking history is in the PACU after an open hemicolectomy. She is somnolent but arousable on a 40% Venturi mask. The pulse oximeter reads SpO2 98% with a strong plethysmographic waveform, yet she appears dusky and her respiratory rate is 8/min. An arterial blood gas drawn simultaneously shows PaO2 95 mmHg, PaCO2 64 mmHg, pH 7.28, and a co-oximetry carboxyhemoglobin (COHb) level of 22%. Which statement best explains the discrepancy between the reassuring pulse oximeter reading and the patient''s clinical appearance?', '[{"text":"The pulse oximeter is reading falsely high because methemoglobin drives the SpO2 toward 85% regardless of true saturation","label":"A","correct":false,"rationale":"Methemoglobin pulls a standard two-wavelength oximeter toward roughly 85%, not 98%, and the elevated species here is carboxyhemoglobin, not methemoglobin."},{"text":"The strong plethysmographic waveform confirms the SpO2 is accurate, so the dusky appearance must be from peripheral vasoconstriction alone","label":"B","correct":false,"rationale":"A good waveform confirms an adequate pulsatile signal but says nothing about whether absorbed light is being misattributed to oxyhemoglobin, so it cannot validate accuracy in the presence of dyshemoglobins."},{"text":"The elevated PaCO2 has shifted the oxyhemoglobin dissociation curve, causing the oximeter to overread saturation","label":"C","correct":false,"rationale":"A rightward Bohr shift changes the PaO2 at which hemoglobin is saturated but does not cause the optical overestimation seen here; the oximeter error is due to the dyshemoglobin, not the curve position."},{"text":"Because PaO2 is normal at 95 mmHg, the SpO2 of 98% is appropriate and no occult abnormality is present","label":"D","correct":false,"rationale":"PaO2 reflects dissolved oxygen tension, not hemoglobin''s oxygen-carrying capacity, so a normal PaO2 cannot reassure when 22% of hemoglobin is bound to carbon monoxide and unavailable for transport."},{"text":"A conventional two-wavelength pulse oximeter cannot distinguish carboxyhemoglobin from oxyhemoglobin, so it overestimates true oxygen saturation when COHb is elevated","label":"E","correct":true,"rationale":"Carboxyhemoglobin absorbs 660-nm light almost identically to oxyhemoglobin, so a two-wavelength device counts COHb as oxyhemoglobin and reports a falsely high SpO2."}]'::jsonb, 'E', 'Standard pulse oximeters use only two wavelengths (660 nm and 940 nm) and assume blood contains only oxyhemoglobin and deoxyhemoglobin. Carboxyhemoglobin absorbs light at 660 nm almost identically to oxyhemoglobin, so the device misclassifies it as saturated hemoglobin and reports a falsely elevated SpO2 that can remain near normal even with dangerous CO poisoning. Co-oximetry, which uses multiple wavelengths, is required to measure dyshemoglobins, and clinical context (smoke or combustion exposure, headache, somnolence) should prompt its use rather than relying on a reassuring SpO2.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK470348/","source":"Pulse Oximetry (StatPearls, NCBI Bookshelf)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-041', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Anesthesia breathing circuit equipment (CO2 absorbent desiccation)', 'hard', 'An anesthesiologist assistant returns from a weekend to find the first scheduled case is a sevoflurane general anesthetic delivered through a circle system that was left with the fresh gas flow inadvertently running at 10 L/min over the entire 36-hour period with the vaporizer off. During the preoperative machine check, the soda lime canister feels warm and its color indicator has reverted from violet back to white. Which step most directly reduces the risk of patient harm from anesthetic degradation in this circuit?', '[{"text":"Replace the desiccated absorbent with fresh, properly hydrated absorbent before beginning the anesthetic","label":"A","correct":true,"rationale":"Desiccation is the root cause of accelerated anesthetic breakdown to carbon monoxide and Compound A, so installing fresh hydrated absorbent removes the conditions that generate these toxins."},{"text":"Increase the fresh gas flow during the case to dilute any toxic degradation products that form","label":"B","correct":false,"rationale":"High fresh gas flow through desiccated absorbent does not eliminate the chemistry of degradation and can actually accelerate further drying and exothermic reaction, so it does not reliably protect the patient."},{"text":"Switch the planned agent from sevoflurane to desflurane to avoid Compound A formation","label":"C","correct":false,"rationale":"Desflurane and desiccated strong-base absorbent is the combination most prone to generating high carbon monoxide concentrations, so substituting desflurane trades one hazard for a worse one."},{"text":"Proceed with the case because the reverted (white) color indicator confirms the absorbent is fully regenerated and safe","label":"D","correct":false,"rationale":"Color indicators track pH-driven exhaustion and can revert on standing even when granules remain dangerously desiccated, so a white color does not confirm safety."},{"text":"Add a heat-and-moisture exchanger to the breathing circuit to rehydrate the absorbent during use","label":"E","correct":false,"rationale":"An HME humidifies inspired gas at the patient connection but does not restore water content to the absorbent granules upstream, so it does not correct the desiccation driving degradation."}]'::jsonb, 'A', 'Prolonged high fresh gas flow desiccates carbon dioxide absorbent, and dry strong-base absorbents (those containing sodium or potassium hydroxide) degrade volatile anesthetics into toxic products: sevoflurane forms Compound A (a nephrotoxin) and, more importantly, desiccated absorbent with any agent can generate carbon monoxide, with desflurane producing the highest concentrations. A warm canister and a reverted color indicator are classic warning signs of a desiccated, reacting absorbent. The definitive remedy is to replace the absorbent with fresh hydrated material; modern calcium-hydroxide-based absorbents (e.g., Amsorb) lack strong bases and produce negligible CO and Compound A even when dry.', '[{"url":"https://www.openanesthesia.org/keywords/carbon-dioxide-absorbers/","source":"Carbon Dioxide Absorbers (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-042', 'Monitoring, Equipment & Physiology', 'Monitoring, Equipment & Physiology', 'Subspecialty Care', 'Neuromuscular monitoring (quantitative vs qualitative train-of-four)', 'medium', 'A 71-year-old man with chronic kidney disease undergoes a 3-hour laparoscopic nephrectomy under general anesthesia with rocuronium. At the end of the case the surgeon is closing, and you plan to reverse neuromuscular blockade with neostigmine and glycopyrrolate. Using a qualitative (visual/tactile) peripheral nerve stimulator at the ulnar nerve, you observe 4 of 4 twitches on train-of-four with no detectable fade by hand. The patient is normothermic. Which statement most accurately describes the limitation of this assessment for confirming readiness for extubation?', '[{"text":"A qualitative train-of-four count of 4 with no tactile fade reliably confirms a train-of-four ratio of at least 0.9 and full recovery","label":"A","correct":false,"rationale":"Tactile and visual assessment cannot detect fade once the ratio exceeds roughly 0.4, so 4 twitches without perceived fade is fully compatible with a ratio well below the 0.9 threshold."},{"text":"Quantitative (objective) monitoring is required to confirm a train-of-four ratio of 0.9 or greater, because qualitative assessment cannot detect fade in this range","label":"B","correct":true,"rationale":"Only objective monitors measure the actual twitch-amplitude ratio, and a ratio of at least 0.9 is the validated threshold for adequate recovery that qualitative methods cannot verify."},{"text":"Neostigmine should not be given because a count of 4 of 4 means no residual blockade remains to reverse","label":"C","correct":false,"rationale":"A qualitative count of 4 does not exclude clinically significant residual blockade, and withholding reversal in that setting risks postoperative residual weakness rather than confirming safety."},{"text":"Double-burst stimulation is less sensitive than train-of-four for detecting residual blockade by hand and should not be used","label":"D","correct":false,"rationale":"Double-burst stimulation actually improves tactile detection of fade compared with train-of-four, so this reverses the true relationship between the two qualitative methods."},{"text":"Switching the stimulation site to the facial nerve would give a more conservative estimate of peripheral recovery than the adductor pollicis","label":"E","correct":false,"rationale":"Facial (orbicularis oculi) muscles recover earlier than the adductor pollicis and overestimate recovery, so monitoring there is less conservative and can mask residual peripheral weakness."}]'::jsonb, 'B', 'The train-of-four ratio (the amplitude of the fourth twitch divided by the first) must be 0.9 or greater to confirm adequate recovery and minimize the risk of residual neuromuscular blockade. Human observers can detect fade by sight or touch only up to a ratio of about 0.4; beyond that, a qualitative ''no fade, 4 of 4'' is indistinguishable from a ratio of 0.5 to 0.9, all of which represent inadequate recovery. Quantitative monitors (acceleromyography, electromyography) objectively measure the ratio, and current ASA guidance recommends quantitative monitoring to confirm a ratio of at least 0.9 before extubation, which is especially important in this patient given renal impairment that prolongs rocuronium clearance.', '[{"url":"https://www.openanesthesia.org/keywords/monitoring-depth-of-neuromuscular-blockade/","source":"Monitoring Depth of Neuromuscular Blockade (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-043', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Age-related pharmacology of IV anesthetics (propofol induction dosing)', 'medium', 'An 82-year-old, 60-kg woman with hypertension and mild chronic kidney disease presents for elective open reduction and internal fixation of a hip fracture. She is alert and cooperative. Baseline vitals: blood pressure 138/76 mmHg, heart rate 72/min, SpO2 96% on room air. The anesthesiologist plans a propofol induction. Compared with a healthy 30-year-old, which adjustment to the propofol induction dose and a correct underlying mechanism best applies to this patient?', '[{"text":"Increase the dose by 30%, because reduced lean body mass enlarges the central compartment and lowers peak plasma concentration","label":"A","correct":false,"rationale":"Incorrect; aging reduces central volume of distribution and increases pharmacodynamic sensitivity, so the required dose falls rather than rises."},{"text":"Use the same weight-based dose, because propofol pharmacodynamics are unchanged by age once dosing is corrected for body weight","label":"B","correct":false,"rationale":"Incorrect; elderly patients are roughly 30% more pharmacodynamically sensitive to propofol independent of weight-based correction, so an unchanged dose risks profound hypotension."},{"text":"Reduce the dose by approximately 40-50% and titrate slowly, because elderly patients have increased pharmacodynamic sensitivity and reduced clearance","label":"C","correct":true,"rationale":"Correct; geriatric patients are about 30% more sensitive to propofol and have slower clearance, so a 40-50% induction-dose reduction with slow titration is recommended."},{"text":"Reduce the dose by 10% only, because the sole relevant change is a modest decline in hepatic blood flow that minimally affects induction","label":"D","correct":false,"rationale":"Incorrect; a 10% reduction underestimates the combined pharmacodynamic and pharmacokinetic changes of aging and still predisposes to hemodynamic collapse."},{"text":"Avoid propofol entirely and substitute full-dose etomidate, because the elderly show markedly increased pharmacodynamic sensitivity to etomidate","label":"E","correct":false,"rationale":"Incorrect; the elderly do NOT show increased pharmacodynamic sensitivity to etomidate (its dose reduction is driven by altered clearance), so this rationale is wrong even though etomidate can be a reasonable hemodynamic choice."}]'::jsonb, 'C', 'Aging produces both pharmacokinetic changes (smaller central compartment, reduced clearance, increased body fat) and pharmacodynamic changes (about 30% greater brain sensitivity) for propofol. The net effect is that elderly patients require substantially less propofol for induction, and the dose should be reduced roughly 40-50% and given slowly to avoid exaggerated hypotension. Notably, the increased sensitivity is agent-specific: etomidate dose reductions in the elderly are driven by altered clearance, not heightened pharmacodynamic sensitivity.', '[{"url":"https://www.openanesthesia.org/keywords/pharmacological-changes-with-aging-inhalational-and-intravenous-anesthetics/","source":"Pharmacological Changes With Aging: Inhalational and Intravenous Anesthetics (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-044', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Postoperative delirium prevention and management', 'easy', 'A 79-year-old man with hypertension and baseline mild cognitive impairment undergoes uncomplicated colonic resection under general anesthesia. On postoperative day 2 he becomes acutely confused and inattentive, with fluctuating consciousness and visual hallucinations that worsen at night. He is afebrile, SpO2 is 95% on 2 L/min nasal cannula, basic metabolic panel and glucose are normal, and his bladder is not distended. He is agitated and pulling at lines. Which intervention is the most appropriate FIRST step in management?', '[{"text":"Administer a scheduled benzodiazepine such as lorazepam to control agitation and promote sleep","label":"A","correct":false,"rationale":"Incorrect; benzodiazepines are a recognized precipitant of delirium in the elderly and typically worsen, not improve, the condition."},{"text":"Start scheduled diphenhydramine at bedtime to treat the nocturnal worsening","label":"B","correct":false,"rationale":"Incorrect; anticholinergic agents like diphenhydramine reduce central cholinergic tone and can precipitate or aggravate delirium in older adults."},{"text":"Apply physical (wrist) restraints to prevent line removal and ensure safety","label":"C","correct":false,"rationale":"Incorrect; restraints are associated with prolonged and more severe delirium and should be avoided except as a brief last resort when safety cannot otherwise be ensured."},{"text":"Implement nonpharmacologic measures: reorientation, restore hearing/visual aids, normalize the sleep-wake cycle, and mobilize early","label":"D","correct":true,"rationale":"Correct; multicomponent nonpharmacologic strategies are first-line for postoperative delirium and address the modifiable precipitating factors before drugs are considered."},{"text":"Order an urgent head CT to evaluate for a structural cause before any other intervention","label":"E","correct":false,"rationale":"Incorrect; with a classic fluctuating presentation and no focal deficits or red flags, imaging is low-yield as the first step, whereas reversible precipitants and nonpharmacologic care take priority."}]'::jsonb, 'D', 'Postoperative delirium is an acute, fluctuating disturbance of attention and awareness common in older surgical patients, and management begins with identifying and correcting precipitants (hypoxia, pain, infection, metabolic derangement, urinary retention) combined with multicomponent nonpharmacologic care. Reorientation, sensory aids, sleep-wake normalization, and early mobilization are first-line. Deliriogenic drugs such as benzodiazepines and anticholinergics should be avoided, and physical restraints can worsen and prolong delirium.', '[{"url":"https://www.openanesthesia.org/keywords/postoperative-delirium/","source":"Postoperative Delirium in the Aging Patient (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-045', 'Geriatric', 'Geriatric', 'Subspecialty Care', 'Perioperative cardiovascular risk management (beta-blocker continuation vs initiation)', 'hard', 'A 75-year-old man with stable coronary artery disease, hypertension, and a remote drug-eluting stent presents for elective open inguinal hernia repair. He has taken metoprolol succinate 100 mg daily for three years; his resting heart rate is 58/min and blood pressure is 132/74 mmHg. The surgical resident asks whether to hold the metoprolol on the morning of surgery and whether a new high-dose beta-blocker should be started preoperatively to further lower cardiac risk. What is the most appropriate perioperative beta-blocker management?', '[{"text":"Hold the metoprolol on the morning of surgery and resume it postoperatively to prevent intraoperative bradycardia","label":"A","correct":false,"rationale":"Incorrect; abruptly stopping chronic beta-blockade risks rebound tachycardia, hypertension, and ischemia, so it should be continued rather than held."},{"text":"Continue the metoprolol and additionally start high-dose extended-release metoprolol the morning of surgery to maximize cardioprotection","label":"B","correct":false,"rationale":"Incorrect; starting high-dose beta-blockade on the day of surgery is exactly the POISE regimen that reduced nonfatal MI but increased total mortality and stroke."},{"text":"Discontinue the metoprolol one week before surgery to allow full recovery of chronotropic reserve","label":"C","correct":false,"rationale":"Incorrect; planned discontinuation of chronic beta-blockade removes its protective effect and risks withdrawal phenomena and perioperative ischemia."},{"text":"Switch him to a single preoperative dose of intravenous esmolol on arrival in place of his oral metoprolol","label":"D","correct":false,"rationale":"Incorrect; there is no indication to replace effective stable oral therapy with a short-acting agent, and this does not address the core question of continuation versus new initiation."},{"text":"Continue his chronic metoprolol through the perioperative period and do NOT initiate a new high-dose beta-blocker","label":"E","correct":true,"rationale":"Correct; chronic beta-blockade should be continued to avoid withdrawal, while fresh high-dose initiation just before surgery increased stroke and mortality in the POISE trial and is not recommended."}]'::jsonb, 'E', 'Patients already on chronic beta-blockers should have them continued throughout the perioperative period, because abrupt withdrawal causes rebound adrenergic activity and ischemia. In contrast, de novo initiation of high-dose beta-blockade shortly before noncardiac surgery is harmful: the POISE trial showed that fixed high-dose metoprolol started just before surgery reduced nonfatal MI but increased overall mortality and stroke, largely from hypotension and bradycardia. This continue-but-do-not-newly-initiate principle is especially relevant in older patients with established coronary disease.', '[{"url":"https://www.openanesthesia.org/keywords/perioperative-myocardial-infarction/","source":"Perioperative Myocardial Infarction (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb);
